  1→import { useState, useEffect, useRef, useCallback, useMemo } from "react";
  2→import type { SessionPanelRef } from "@/features/session";
  3→import { NewWorkspaceModal, CloneRepositoryModal } from "@/features/repository";
  4→import { SystemPromptModal } from "@/features/session";
  5→import { SettingsSidebar, SettingsPage } from "@/features/settings";
  6→import {
  7→  useKeyboardShortcuts,
  8→  useZoom,
  9→  useIsFullscreen,
 10→  useWindowDragZone,
 11→  useWindowResizing,
 12→} from "@/shared/hooks";
 13→import {
 14→  useWorkspacesByRepo,
 15→  useBulkDiffStats,
 16→  usePRStatus,
 17→  useGhStatus,
 18→  useArchiveWorkspace,
 19→  useUnarchiveWorkspace,
 20→  useUpdateWorkspaceStatus,
 21→} from "@/features/workspace/api";
 22→import { useResizeHandle } from "@/features/workspace";
 23→import { useRepos } from "@/features/repository/api";
 24→import { useSettings as useSettingsQuery } from "@/features/settings";
 25→import { SidebarProvider, useSidebar } from "@/components/ui";
 26→import { AppSidebar, SidebarSkeleton } from "@/features/sidebar";
 27→import { useWorkspaceStore } from "@/features/workspace/store";
 28→import { useUIStore } from "@/shared/stores/uiStore";
 29→import {
 30→  useChatInsertStore,
 31→  chatInsertActions,
 32→  deliverChatInsertPayload,
 33→  deserializeChatInsertPayload,
 34→  isChatInsertForWorkspace,
 35→} from "@/shared/stores/chatInsertStore";
 36→import { ResizeHandle } from "@/shared/components/ResizeHandle";
 37→import type { Workspace } from "@/shared/types";
 38→import { native } from "@/platform";
 39→import { CHAT_INSERT } from "@shared/events";
 40→import { CommandPalette } from "@/features/command-palette";
 41→import { GitHubPickerModal } from "@/features/sidebar/ui/GitHubPickerModal";
 42→import { MainContent } from "./MainContent";
 43→import { useRepoActions } from "./hooks/useRepoActions";
 44→import { useSystemPrompt, useUpdateSystemPrompt } from "@/features/workspace/api";
 45→import { toast } from "sonner";
 46→import { getErrorMessage } from "@shared/lib/errors";
 47→
 48→/**
 49→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 50→ * Must be rendered inside SidebarProvider to access sidebar open state.
 51→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 52→ */
 53→function SidebarResizeHandle({
 54→  onSizeChange,
 55→  onDraggingChange,
 56→}: {
 57→  onSizeChange: (size: number | null) => void;
 58→  onDraggingChange: (dragging: boolean) => void;
 59→}) {
 60→  const { open } = useSidebar();
 61→
 62→  const { handleProps, isDragging } = useResizeHandle({
 63→    onSizeChange,
 64→    enabled: open,
 65→    direction: "horizontal",
 66→    mode: "primary",
 67→    minPrimarySize: 200,
 68→    minSecondarySize: 400,
 69→  });
 70→
 71→  // Notify parent of drag state changes to disable sidebar transitions
 72→  useEffect(() => {
 73→    onDraggingChange(isDragging);
 74→  }, [isDragging, onDraggingChange]);
 75→
 76→  if (!open) return null;
 77→
 78→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 79→}
 80→
 81→export function MainLayout() {
 82→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 83→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 84→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 85→
 86→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
 87→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
 88→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
 89→  const settingsOpen = useUIStore((s) => s.settingsOpen);
 90→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
 91→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
 92→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
 93→
 94→  // TanStack Query
 95→  const workspacesQuery = useWorkspacesByRepo();
 96→
 97→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
 98→  const loading = workspacesQuery.isLoading;
 99→
100→  // Derive the full workspace object from React Query data.
101→  // The store only holds an ID; this useMemo resolves it to a Workspace
102→  // on every React Query refresh, eliminating the old sync effect entirely.
103→  const selectedWorkspace = useMemo(() => {
104→    if (!selectedWorkspaceId || !repoGroups.length) return null;
105→    for (const group of repoGroups) {
106→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
107→      if (found) return found;
108→    }
109→    return null;
110→  }, [selectedWorkspaceId, repoGroups]);
111→
112→  const selectedWorkspaceIdRef = useRef(selectedWorkspaceId);
113→  useEffect(() => {
114→    selectedWorkspaceIdRef.current = selectedWorkspaceId;
115→  });
116→
117→  // Bulk-fetch diff stats for all workspaces (replaces per-item useDiffStats in sidebar)
118→  const bulkDiffStatsQuery = useBulkDiffStats(repoGroups);
119→
120→  // Sidebar resize: null = default 344px, number = user-set width
121→  const [sidebarWidth, setSidebarWidth] = useState<number | null>(null);
122→  // Tracks drag state to disable sidebar CSS transitions during resize
123→  const [sidebarDragging, setSidebarDragging] = useState(false);
124→
125→  // GitHub picker modal state
126→  const [githubPickerRepoId, setGithubPickerRepoId] = useState<string | null>(null);
127→
128→  // Ref for inserting text from browser element selector
129→  const workspaceChatPanelRef = useRef<SessionPanelRef | null>(null);
130→
131→  // Queries for repos, settings
132→  const reposQuery = useRepos();
133→  const settingsQuery = useSettingsQuery();
134→
135→  const repos = reposQuery.data || [];
136→  const username = settingsQuery.data?.user_name || "My Account";
137→
138→  // GitHub CLI status — gates PR polling (like Codex)
139→  const ghStatusQuery = useGhStatus();
140→
141→  // PR status query — gated on gh CLI, polls while agent is working
142→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
143→    ghInstalled: ghStatusQuery.data?.isInstalled,
144→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
145→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
146→  });
147→
148→  // --- Extracted hooks ---
149→
150→  const repoActions = useRepoActions({
151→    selectWorkspace,
152→    openNewWorkspaceModal,
153→    closeNewWorkspaceModal,
154→  });
155→
156→  // Derive repo name for GitHub picker modal from repoGroups
157→  const githubPickerRepoName = useMemo(() => {
158→    if (!githubPickerRepoId) return "";
159→    const group = repoGroups.find((g) => g.repo_id === githubPickerRepoId);
160→    return group?.repo_name ?? "";
161→  }, [githubPickerRepoId, repoGroups]);
162→
163→  // Hide native WebContentsViews when any dialog is open — they render above
164→  // the DOM so dialogs would appear behind them. BrowserTab's own visible
165→  // effect handles re-showing when the dialog closes.
166→  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
167→  const anyDialogOpen =
168→    showNewWorkspaceModal ||
169→    showSystemPromptModal ||
170→    commandPaletteOpen ||
171→    !!githubPickerRepoId ||
172→    repoActions.showCloneModal;
173→  useEffect(() => {
174→    if (anyDialogOpen) {
175→      native.browserViews.hideAll().catch(() => {});
176→    }
177→  }, [anyDialogOpen]);
178→
179→  // --- System prompt (inline — small scope, one modal) ---
180→
181→  const systemPromptQuery = useSystemPrompt(selectedWorkspace?.id || null);
182→  const updateSystemPromptMutation = useUpdateSystemPrompt();
183→  // Track user edits separately; reset to null when modal closes so the
184→  // derived value from the query takes over again (no useEffect + setState).
185→  const [systemPromptEdit, setSystemPromptEdit] = useState<string | null>(null);
186→  const systemPromptDraft = systemPromptEdit ?? (systemPromptQuery.data || "");
187→  const setSystemPromptDraft = useCallback((value: string) => setSystemPromptEdit(value), []);
188→
189→  async function saveSystemPrompt() {
190→    if (!selectedWorkspace) return;
191→    try {
192→      await updateSystemPromptMutation.mutateAsync({
193→        workspaceId: selectedWorkspace.id,
194→        systemPrompt: systemPromptDraft,
195→      });
196→      closeSystemPromptModal();
197→      setSystemPromptEdit(null);
198→    } catch (error) {
199→      console.error("Failed to save system prompt:", error);
200→      toast.error(getErrorMessage(error));
201→    }
202→  }
203→
204→  // --- Archive with undo (ref-stable for memoized sidebar items) ---
205→
206→  const archiveWorkspaceMutation = useArchiveWorkspace();
207→  const unarchiveMutation = useUnarchiveWorkspace();
208→
209→  // Ref-stable archive handler: archiveWorkspaceMutation and selectedWorkspace
210→  // change frequently (every render / every workspace click), so we capture
211→  // them in refs to keep the callback identity stable. This matters because
212→  // onArchive flows through the entire sidebar tree to every memoized WorkspaceItem.
213→  const archiveMutationRef = useRef(archiveWorkspaceMutation);
214→  const unarchiveMutationRef = useRef(unarchiveMutation);
215→  const selectedWorkspaceRef = useRef(selectedWorkspace);
216→  useEffect(() => {
217→    archiveMutationRef.current = archiveWorkspaceMutation;
218→    unarchiveMutationRef.current = unarchiveMutation;
219→    selectedWorkspaceRef.current = selectedWorkspace;
220→  });
221→
222→  const archiveWorkspace = useCallback(
223→    async (workspaceId: string) => {
224→      try {
225→        await archiveMutationRef.current.mutateAsync(workspaceId);
226→        if (selectedWorkspaceRef.current?.id === workspaceId) {
227→          selectWorkspace(null);
228→        }
229→        toast("Workspace archived", {
230→          duration: 5000,
231→          action: {
232→            label: "Undo",
233→            onClick: () => {
234→              unarchiveMutationRef.current.mutateAsync(workspaceId).catch((error) => {
235→                toast.error(getErrorMessage(error));
236→              });
237→            },
238→          },
239→        });
240→      } catch (error) {
241→        console.error("Error archiving workspace:", error);
242→        toast.error(getErrorMessage(error));
243→      }
244→    },
245→    [selectWorkspace]
246→  );
247→
248→  // --- Workflow status change (ref-stable like archive) ---
249→
250→  const statusMutation = useUpdateWorkspaceStatus();
251→  const statusMutationRef = useRef(statusMutation);
252→  useEffect(() => {
253→    statusMutationRef.current = statusMutation;
254→  });
255→
256→  const handleStatusChange = useCallback(
257→    (workspaceId: string, status: import("@shared/enums").WorkspaceStatus) => {
258→      statusMutationRef.current.mutate(
259→        { workspaceId, status },
260→        { onError: (error) => toast.error(getErrorMessage(error)) }
261→      );
262→    },
263→    []
264→  );
265→
266→  // --- Global hooks ---
267→
268→  // Zoom (Cmd+=/Cmd+-/Cmd+0)
269→  useZoom();
270→
271→  // Track fullscreen state — toggles `.fullscreen` class on <html> for CSS
272→  useIsFullscreen();
273→
274→  // Adds .electron class to <html> and injects CSS-only drag region rules.
275→  // Headers with .drag-region class become draggable; buttons auto-excluded.
276→  useWindowDragZone();
277→
278→  // Disable CSS transitions during native window resize to prevent content "sticking"
279→  useWindowResizing();
280→
281→  // Keyboard shortcuts
282→  useKeyboardShortcuts({
283→    onRefresh: async () => {
284→      workspacesQuery.refetch();
285→      if (selectedWorkspace) {
286→        prStatusQuery.refetch();
287→      }
288→    },
289→    onEscape: () => {
290→      if (showNewWorkspaceModal) {
291→        closeNewWorkspaceModal();
292→      } else if (showSystemPromptModal) {
293→        closeSystemPromptModal();
294→      }
295→    },
296→    selectedWorkspace,
297→    modalStates: {
298→      showNewWorkspaceModal,
299→      showSystemPromptModal,
300→    },
301→  });
302→
303→  // Subscribe to chatInsertStore for content dispatched from BrowserPanel / DiffViewer / SimulatorPanel
304→  useEffect(() => {
305→    const unsubStore = useChatInsertStore.subscribe((state, prevState) => {
306→      if (!state.pending || state.pending === prevState.pending) return;
307→
308→      const payload = state.pending;
309→      chatInsertActions.consume();
310→
311→      if (!workspaceChatPanelRef.current) return;
312→      if (!isChatInsertForWorkspace(payload, selectedWorkspaceIdRef.current)) return;
313→
314→      deliverChatInsertPayload(workspaceChatPanelRef.current, payload);
315→    });
316→
317→    const unlistenChat = native.events.on(CHAT_INSERT, (data) => {
318→      void deserializeChatInsertPayload(data)
319→        .then((payload) => {
320→          chatInsertActions.dispatch(payload);
321→        })
322→        .catch((error) => {
323→          console.error("Failed to deserialize detached chat insert:", error);
324→        });
325→    });
326→
327→    return () => {
328→      unsubStore();
329→      unlistenChat();
330→    };
331→  }, []);
332→
333→  const handleWorkspaceClick = useCallback(
334→    (workspace: Workspace) => {
335→      selectWorkspace(workspace.id);
336→    },
337→    [selectWorkspace]
338→  );
339→
340→  return (
341→    <SidebarProvider
342→      className="h-full"
343→      data-resizing={sidebarDragging || undefined}
344→      style={
345→        {
346→          "--sidebar-width": sidebarWidth ? `${sidebarWidth}px` : "344px",
347→          "--sidebar-width-mobile": "344px",
348→        } as React.CSSProperties
349→      }
350→    >
351→      {/* Sidebar — swap between app sidebar and settings sidebar */}
352→      {settingsOpen ? (
353→        <SettingsSidebar />
354→      ) : loading ? (
355→        <SidebarSkeleton />
356→      ) : (
357→        <AppSidebar
358→          repositories={repoGroups}
359→          selectedWorkspaceId={selectedWorkspace?.id || null}
360→          diffStatsMap={bulkDiffStatsQuery.data}
361→          onWorkspaceClick={handleWorkspaceClick}
362→          onNewWorkspace={repoActions.handleNewWorkspace}
363→          onNewWorkspaceFromGitHub={setGithubPickerRepoId}
364→          onAddRepository={repoActions.handleOpenProject}
365→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
366→          onArchive={archiveWorkspace}
367→          onStatusChange={handleStatusChange}
368→          profile={{ username }}
369→        />
370→      )}
