 61→
 62→// ---- Singleton State ----
 63→
 64→let ws: WebSocket | null = null;
 65→let _connectionId: string | null = null;
 66→let connected = false;
 67→let connecting = false;
 68→let reconnectAttempt = 0;
 69→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 70→let subCounter = 0;
 71→
 72→/** Active subscriptions keyed by client-assigned ID. */
 73→const subscriptions = new Map<string, Subscription>();
 74→
 75→/** Pending commands waiting for q:command_ack. */
 76→const pendingCommands = new Map<string, PendingCommand>();
 77→
 78→/** Pending one-shot q:request frames waiting for q:response. */
 79→const pendingRequests = new Map<string, PendingRequest>();
 80→
 81→/** Pending q:mutate frames waiting for q:mutate_result. */
 82→const pendingMutations = new Map<string, PendingMutation>();
 83→
 84→/** Listeners for q:event broadcasts. */
 85→const eventListeners = new Set<EventCallback>();
 86→
 87→/** Listeners notified when connection state changes (connected/disconnected). */
 88→const connectionChangeListeners = new Set<(connected: boolean) => void>();
 89→
 90→/** Counter for generating unique command frame IDs. */
 91→let commandCounter = 0;
 92→
 93→/** Counter for generating unique request/mutation frame IDs. */
 94→let requestCounter = 0;
 95→
 96→/** Resolvers waiting for the initial "connected" frame after open. */
 97→let connectResolve: (() => void) | null = null;
 98→let connectReject: ((err: Error) => void) | null = null;
 99→
100→// ---- Public API ----
101→
102→/** Generate a unique subscription ID. */
103→function nextSubId(): string {
104→  return `sub_${++subCounter}`;
105→}
106→
107→/**
108→ * Connect to the backend WebSocket. Resolves once authenticated.
109→ * No-op if already connected or connecting.
110→ *
111→ * In relay mode, pass the serverId so the WS URL can be resolved.
112→ */
113→export async function connect(serverId?: string): Promise<void> {
114→  if (connected) return;
115→  if (connecting) {
116→    // Wait for the in-flight connection attempt
117→    return new Promise<void>((resolve, reject) => {
118→      const prevResolve = connectResolve;
119→      const prevReject = connectReject;
120→      connectResolve = () => {
121→        prevResolve?.();
122→        resolve();
123→      };
124→      connectReject = (err) => {
125→        prevReject?.(err);
126→        reject(err);
127→      };
128→    });
129→  }
130→
131→  connecting = true;
132→
133→  return new Promise<void>((resolve, reject) => {
