222→/**
223→ * Send a one-shot data request via the q:request frame.
224→ * Returns a promise that resolves with the response data when the
225→ * server sends q:response, or rejects on q:error or timeout.
226→ *
227→ * Works with both subscribable (QueryResource) and request-only
228→ * (RequestResource) resources.
229→ */
230→export function sendRequest<T = unknown>(
231→  resource: string,
232→  params?: Record<string, unknown>
233→): Promise<T> {
234→  const id = `req_${++requestCounter}`;
235→  const REQUEST_TIMEOUT_MS = 30_000;
236→
237→  return new Promise<T>((resolve, reject) => {
238→    const timer = setTimeout(() => {
239→      pendingRequests.delete(id);
240→      reject(new Error(`Request ${resource} timed out`));
241→    }, REQUEST_TIMEOUT_MS);
242→
243→    pendingRequests.set(id, {
244→      resolve: resolve as (data: unknown) => void,
245→      reject,
246→      timer,
247→    });
248→
249→    const sent = sendFrame({
250→      type: "q:request",
251→      id,
252→      resource,
253→      ...(params ? { params } : {}),
254→    });
255→
256→    if (!sent) {
257→      clearTimeout(timer);
258→      pendingRequests.delete(id);
259→      reject(new Error("WebSocket not connected"));
260→    }
261→  });
262→}
