270→  action: string,
271→  params: Record<string, unknown>
272→): Promise<{ success: boolean; data?: T; error?: string }> {
273→  const id = `mut_${++requestCounter}`;
274→  const MUTATE_TIMEOUT_MS = 30_000;
275→
276→  return new Promise((resolve, reject) => {
277→    const timer = setTimeout(() => {
278→      pendingMutations.delete(id);
279→      reject(new Error(`Mutation ${action} timed out`));
280→    }, MUTATE_TIMEOUT_MS);
281→
282→    pendingMutations.set(id, {
283→      resolve: resolve as (result: { success: boolean; data?: unknown; error?: string }) => void,
284→      reject,
285→      timer,
286→    });
287→
288→    const sent = sendFrame({
289→      type: "q:mutate",
290→      id,
291→      action,
292→      params,
293→    });
