400→      } else {
401→        // No token available — close and surface auth failure
402→        console.error("[WS] Relay mode: no device token available for authentication");
403→        ws?.close(4001, "No device token");
404→      }
405→    }
406→    // Localhost/web-dev connections are auto-authenticated by the backend.
407→    // Wait for the "connected" frame in onmessage.
408→  };
409→
410→  ws.onmessage = (evt) => {
411→    let msg: Record<string, unknown>;
412→    try {
