 1→/**
 2→ * BackendStatusIndicator — shows a red dot + label when the backend WebSocket is disconnected.
 3→ * Renders nothing when connected (absence = healthy), same pattern as AIStatusIndicator.
 4→ */
 5→
 6→import { useState, useEffect } from "react";
 7→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
 8→import { isConnected, onConnectionChange } from "@/platform/ws";
 9→
10→const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
11→
12→export function BackendStatusIndicator() {
13→  const [connected, setConnected] = useState(isConnected());
14→  const reduceMotion = useReducedMotion();
15→
16→  useEffect(() => onConnectionChange(setConnected), []);
17→
18→  return (
19→    <AnimatePresence>
20→      {!connected && (
21→        <m.div
22→          key="backend-status"
23→          initial={reduceMotion ? false : { opacity: 0, scale: 0.8 }}
24→          animate={{ opacity: 1, scale: 1 }}
25→          exit={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.8 }}
26→          transition={{ duration: reduceMotion ? 0 : 0.2, ease: EASE_OUT_QUART }}
27→          className="flex items-center gap-1.5 px-1 py-0.5"
28→          aria-label="Server disconnected"
29→          role="status"
30→          aria-live="polite"
31→        >
32→          <span className="relative flex h-2 w-2 items-center justify-center">
33→            <span className="bg-accent-red absolute inline-flex h-full w-full animate-ping rounded-full opacity-60" />
34→            <span className="bg-accent-red relative inline-flex h-2 w-2 rounded-full" />
35→          </span>
36→          <span className="text-text-muted text-xs">Server disconnected</span>
