  1→/**
  2→ * ServerLayout -- web mode shell for a connected server.
  3→ *
  4→ * Wraps routes under /s/$serverId. Handles:
  5→ * - Auth gate: shows PairGatePage for unauthenticated relay clients
  6→ * - Relay WebSocket connection with serverId for endpoint resolution
  7→ * - Connection state UI (connecting, offline, reconnecting)
  8→ *
  9→ * The auth gate renders BEFORE the WS connect hooks fire so we don't
 10→ * attempt a tokenless relay connection that would immediately fail.
 11→ */
 12→
 13→import { useEffect } from "react";
 14→import { Outlet, useParams } from "@tanstack/react-router";
 15→import { Toaster } from "@/components/ui/sonner";
 16→import { initNotifications } from "@/platform/notifications";
 17→import { useGlobalSessionNotifications } from "@/features/session/hooks/useGlobalSessionNotifications";
 18→import { useWorkspaceInitEvents } from "@/features/workspace/hooks/useWorkspaceInitEvents";
 19→import { useQueryProtocol } from "@/shared/hooks/useQueryProtocol";
 20→import { useBackendRestart } from "@/shared/hooks/useBackendRestart";
 21→import { useAnalyticsConsent } from "@/platform/analytics";
 22→import { useSettings } from "@/features/settings";
 23→import { useAuth, PairGatePage } from "@/features/auth";
 24→import { isRelayMode } from "@/shared/config/backend.config";
 25→
 26→export function ServerLayout() {
 27→  // Extract serverId from route params for relay WS connection
 28→  const { serverId } = useParams({ strict: false }) as { serverId: string };
 29→
 30→  // Auth gate: relay mode requires device token authentication.
 31→  // This must be checked BEFORE mounting ServerContent, because
 32→  // ServerContent's useQueryProtocol will attempt a WS connect that
 33→  // requires a valid device token in relay mode.
 34→  const auth = useAuth();
 35→  const relay = isRelayMode();
 36→
 37→  // Request OS notification permission once on mount
 38→  useEffect(() => {
 39→    initNotifications();
 40→  }, []);
 41→
 42→  // Auth gate for relay mode: show pairing page if not authenticated
 43→  if (relay) {
 44→    if (auth.isLoading) {
 45→      return (
 46→        <div className="bg-background flex h-screen items-center justify-center">
 47→          <div className="text-muted-foreground text-sm">Checking authentication...</div>
 48→        </div>
 49→      );
 50→    }
 51→    if (!auth.isAuthenticated) {
 52→      return <PairGatePage onPaired={auth.onPaired} serverId={serverId} />;
 53→    }
 54→  }
 55→
 56→  // Auth passed (or not needed) — mount the connected content.
 57→  // ServerContent is a separate component so its hooks only run
 58→  // after the auth gate passes (hooks can't be conditional).
 59→  return <ServerContent serverId={serverId} />;
 60→}
 61→
 62→/**
 63→ * Inner component that runs all the WS + data hooks.
 64→ * Only mounted after the auth gate passes, ensuring we have
 65→ * a valid device token before attempting the relay WS connection.
 66→ */
 67→function ServerContent({ serverId }: { serverId: string }) {
 68→  const settingsQuery = useSettings();
 69→
 70→  // Global listeners -- same as DesktopShell
 71→  useGlobalSessionNotifications();
 72→  useWorkspaceInitEvents();
 73→
 74→  // Pass serverId so the WS URL resolves to the correct relay endpoint
 75→  useQueryProtocol(serverId);
 76→
 77→  useBackendRestart();
 78→  useAnalyticsConsent();
 79→
 80→  // While settings load, show a loading state
 81→  if (settingsQuery.isLoading) {
 82→    return (
 83→      <div className="bg-background flex h-screen items-center justify-center">
 84→        <div className="text-muted-foreground text-sm">Connecting...</div>
 85→      </div>
 86→    );
 87→  }
 88→
 89→  // Backend unreachable
 90→  if (settingsQuery.isError && !settingsQuery.data) {
 91→    return (
 92→      <div className="bg-background flex h-screen items-center justify-center">
 93→        <div className="max-w-md space-y-4 text-center">
 94→          <h1 className="text-foreground text-xl font-semibold">Cannot connect to server</h1>
 95→          <p className="text-muted-foreground text-sm">
 96→            Make sure the OpenDevs desktop app is running and the backend server is started.
 97→          </p>
 98→          <button
 99→            type="button"
100→            onClick={() => settingsQuery.refetch()}
101→            className="bg-primary text-primary-foreground hover:bg-primary/90 rounded-lg px-4 py-2 text-sm font-medium"
102→          >
103→            Retry
104→          </button>
