  1→/**
  2→ * DesktopShell -- Electron desktop mode, no routing.
  3→ *
  4→ * Contains ALL of the existing AppContent gate logic (auth, settings,
  5→ * onboarding, backend error). Renders MainLayout directly without a router.
  6→ *
  7→ * This is the Electron-only code path. Web mode uses TanStack Router instead.
  8→ */
  9→
 10→import { useEffect, useRef } from "react";
 11→import { ErrorBoundary } from "react-error-boundary";
 12→import { MainLayout } from "../layouts/MainLayout";
 13→import { DashboardError } from "@/shared/components";
 14→import { createBoundaryErrorHandler } from "@/shared/utils/errorReporting";
 15→import { Toaster } from "@/components/ui/sonner";
 16→import { OnboardingOverlay } from "@/features/onboarding";
 17→import { useSettings } from "@/features/settings";
 18→import { useAuth, PairGatePage } from "@/features/auth";
 19→import { native, capabilities } from "@/platform";
 20→import { initNotifications } from "@/platform/notifications";
 21→import { useGlobalSessionNotifications } from "@/features/session/hooks/useGlobalSessionNotifications";
 22→import { useWorkspaceInitEvents } from "@/features/workspace/hooks/useWorkspaceInitEvents";
 23→import { useQueryProtocol } from "@/shared/hooks/useQueryProtocol";
 24→import { useBackendRestart } from "@/shared/hooks/useBackendRestart";
 25→import { useAutoUpdate, useUpdateToast, UpdateProvider } from "@/features/updates";
 26→import { useAnalyticsConsent } from "@/platform/analytics";
 27→export function DesktopShell({ reset }: { reset: () => void }) {
 28→  const auth = useAuth();
 29→  const settingsQuery = useSettings();
 30→  const windowShownRef = useRef(false);
 31→
 32→  // Request OS notification permission once on mount
 33→  useEffect(() => {
 34→    initNotifications();
 35→  }, []);
 36→
 37→  // Global listener: fire OS notifications for ALL session events when backgrounded
 38→  useGlobalSessionNotifications();
 39→
 40→  // Global listener: workspace init progress -> invalidate queries on completion
 41→  useWorkspaceInitEvents();
 42→
 43→  // Global listener: WS query protocol -> direct cache updates + invalidation dispatch
 44→  useQueryProtocol();
 45→
 46→  // Global listener: backend restart -> update cached port + force WS reconnect
 47→  useBackendRestart();
 48→
 49→  // Sync PostHog opt-in/out state with analytics_enabled setting
 50→  useAnalyticsConsent();
 51→
 52→  // Auto-update: check on launch + every 5 min, show toast when ready
 53→  const autoUpdate = useAutoUpdate();
 54→  useUpdateToast(autoUpdate);
 55→
 56→  const showOnboarding = !settingsQuery.isError && !settingsQuery.data?.onboarding_completed;
 57→
 58→  // Boot diagnostics -- trace the window-show flow so we can see what's blocking
 59→  useEffect(() => {
 60→    if (import.meta.env.DEV) {
 61→      console.log("[DesktopShell] mount -- auth:", {
 62→        isLoading: auth.isLoading,
 63→        isAuthenticated: auth.isAuthenticated,
 64→      });
 65→      console.log("[DesktopShell] mount -- settings:", {
 66→        isLoading: settingsQuery.isLoading,
 67→        isError: settingsQuery.isError,
 68→        hasData: !!settingsQuery.data,
 69→        onboardingCompleted: settingsQuery.data?.onboarding_completed,
 70→        showOnboarding,
 71→      });
 72→    }
 73→  }, [
 74→    auth.isLoading,
 75→    auth.isAuthenticated,
 76→    settingsQuery.isLoading,
 77→    settingsQuery.isError,
 78→    settingsQuery.data,
 79→    showOnboarding,
 80→  ]);
 81→
 82→  // Show the main window whenever we transition OUT of onboarding.
 83→  useEffect(() => {
 84→    if (settingsQuery.isLoading) return;
 85→    if (showOnboarding) {
 86→      windowShownRef.current = false;
 87→      return;
 88→    }
 89→    if (windowShownRef.current) return;
 90→    native.window.show().catch(console.error);
 91→    windowShownRef.current = true;
 92→  }, [settingsQuery.isLoading, showOnboarding]);
 93→
 94→  // Remote browser auth gate: show pairing page if not authenticated
 95→  if (auth.isLoading) return null;
 96→  if (!auth.isAuthenticated) return <PairGatePage onPaired={auth.onPaired} />;
 97→
 98→  // While settings load, render nothing -- window is hidden anyway
 99→  if (settingsQuery.isLoading) return null;
100→
101→  // Backend unreachable -- show error instead of white screen
102→  if (settingsQuery.isError && !settingsQuery.data) {
103→    return (
104→      <div className="bg-background flex h-screen items-center justify-center">
105→        <div className="max-w-md space-y-4 text-center">
106→          <h1 className="text-foreground text-xl font-semibold">Cannot connect to backend</h1>
107→          <p className="text-muted-foreground text-sm">
108→            {capabilities.windowLifecycle
109→              ? "The backend server failed to start. Check the terminal for errors."
110→              : "Run `bun run dev:web` for browser development, or use the Electron desktop app (`bun run dev`)."}
111→          </p>
112→          <button
113→            type="button"
114→            onClick={() => settingsQuery.refetch()}
115→            className="bg-primary text-primary-foreground hover:bg-primary/90 rounded-lg px-4 py-2 text-sm font-medium"
116→          >
117→            Retry
118→          </button>
119→        </div>
120→      </div>
121→    );
122→  }
123→
124→  if (showOnboarding) {
125→    return <OnboardingOverlay />;
126→  }
127→
128→  return (
129→    <UpdateProvider value={autoUpdate}>
130→      <ErrorBoundary
131→        FallbackComponent={DashboardError}
132→        onReset={reset}
133→        onError={createBoundaryErrorHandler("react.error-boundary.root")}
134→      >
135→        <MainLayout />
136→      </ErrorBoundary>
137→      <Toaster />
138→    </UpdateProvider>
139→  );
140→}
