 1→/**
 2→ * Backend Restart Hook
 3→ *
 4→ * Listens for the "backend:port-changed" IPC event emitted by the Electron
 5→ * main process after the backend crashes and restarts on a new port.
 6→ *
 7→ * On receiving the event:
 8→ * 1. Updates the cached backend port so all future HTTP requests hit the new port
 9→ * 2. Forces an immediate WebSocket reconnect (cancels backoff, closes stale socket)
10→ *
11→ * Without this hook, the renderer would keep retrying the dead old port forever
12→ * because getBackendPort() caches the port from first resolution.
13→ */
14→
15→import { useEffect } from "react";
16→import { native } from "@/platform";
17→import { BACKEND_PORT_CHANGED } from "@shared/events";
18→import { setBackendPort } from "@/shared/config/api.config";
19→import { forceReconnect } from "@/platform/ws/query-protocol-client";
20→
21→export function useBackendRestart() {
22→  useEffect(() => {
23→    const unlisten = native.events.on(BACKEND_PORT_CHANGED, (data) => {
24→      const { port } = data;
25→      console.log(`[BackendRestart] Backend restarted on port ${port}, reconnecting...`);
26→
27→      // 1. Update the cached port so getBackendPort() returns the new value
28→      setBackendPort(port);
29→
30→      // 2. Force immediate WebSocket reconnect to the new port
31→      forceReconnect();
32→    });
33→
34→    return unlisten;
35→  }, []);
36→}
