  1→/**
  2→ * Base API Client
  3→ *
  4→ * Lightweight HTTP client used ONLY for pre-auth endpoints that cannot
  5→ * go through the WebSocket q:* protocol (e.g., /remote-auth/generate-pair-code).
  6→ *
  7→ * All data operations now use sendRequest/sendMutate/sendCommand from @/platform/ws.
  8→ * This client exists solely for the handful of localhost-only HTTP endpoints
  9→ * that run before the WS connection is established.
 10→ */
 11→
 12→import { getBaseURL } from "../config/api.config";
 13→import { getStoredToken, needsRemoteAuth } from "@/features/auth";
 14→import type { ApiError } from "../types";
 15→
 16→const REQUEST_TIMEOUT = 30_000;
 17→
 18→class ApiClient {
 19→  private timeout: number;
 20→
 21→  constructor(timeout: number = REQUEST_TIMEOUT) {
 22→    this.timeout = timeout;
 23→  }
 24→
 25→  /**
 26→   * Generic GET request
 27→   */
 28→  async get<T>(endpoint: string): Promise<T> {
 29→    return this.request<T>(endpoint, { method: "GET" });
 30→  }
 31→
 32→  /**
 33→   * Generic POST request
 34→   */
 35→  async post<T>(endpoint: string, data?: any): Promise<T> {
 36→    return this.request<T>(endpoint, {
 37→      method: "POST",
 38→      headers: { "Content-Type": "application/json" },
 39→      body: data ? JSON.stringify(data) : undefined,
 40→    });
 41→  }
 42→
 43→  /**
 44→   * Generic PUT request
 45→   */
 46→  async put<T>(endpoint: string, data?: any): Promise<T> {
 47→    return this.request<T>(endpoint, {
 48→      method: "PUT",
 49→      headers: { "Content-Type": "application/json" },
 50→      body: data ? JSON.stringify(data) : undefined,
 51→    });
 52→  }
 53→
 54→  /**
 55→   * Generic PATCH request
 56→   */
 57→  async patch<T>(endpoint: string, data: any): Promise<T> {
 58→    return this.request<T>(endpoint, {
 59→      method: "PATCH",
 60→      headers: { "Content-Type": "application/json" },
 61→      body: JSON.stringify(data),
 62→    });
 63→  }
 64→
 65→  /**
 66→   * Generic DELETE request
 67→   */
 68→  async delete<T>(endpoint: string): Promise<T> {
 69→    return this.request<T>(endpoint, { method: "DELETE" });
 70→  }
 71→
 72→  /**
 73→   * Core request method — standard HTTP fetch.
 74→   * Attaches Authorization header for remote browser clients.
 75→   */
 76→  private async request<T>(endpoint: string, options: RequestInit): Promise<T> {
 77→    const baseURL = await getBaseURL();
 78→    const url = `${baseURL}${endpoint}`;
 79→    const controller = new AbortController();
 80→    const timeoutId = setTimeout(() => controller.abort(), this.timeout);
 81→
 82→    // Attach Bearer token for remote (non-localhost) browser sessions
 83→    const headers = new Headers(options.headers);
 84→    if (needsRemoteAuth()) {
 85→      const token = getStoredToken();
 86→      if (token) {
 87→        headers.set("Authorization", `Bearer ${token}`);
 88→      }
 89→    }
 90→
 91→    try {
 92→      const response = await fetch(url, {
 93→        ...options,
 94→        headers,
 95→        signal: controller.signal,
 96→      });
 97→
 98→      clearTimeout(timeoutId);
 99→
100→      if (!response.ok) {
101→        const error: ApiError = {
102→          status: response.status,
103→          message: response.statusText,
104→        };
105→
106→        try {
107→          const errorData = await response.json();
108→          error.details = errorData;
109→          error.message = errorData.error || errorData.message || error.message;
110→        } catch {
111→          // Response is not JSON
112→        }
113→
114→        throw error;
115→      }
116→
117→      // Handle empty responses
118→      const contentType = response.headers.get("content-type");
119→      if (!contentType || !contentType.includes("application/json")) {
120→        return null as T;
121→      }
122→
123→      return await response.json();
124→    } catch (error) {
125→      clearTimeout(timeoutId);
126→
127→      if (error instanceof Error) {
128→        if (error.name === "AbortError") {
129→          throw {
130→            status: 408,
131→            message: "Request timeout",
132→            details: error,
133→          } as ApiError;
134→        }
135→        throw {
136→          status: 0,
137→          message: error.message,
138→          details: error,
139→        } as ApiError;
140→      }
141→
142→      throw error;
143→    }
144→  }
145→}
146→
147→// Export singleton instance
148→export const apiClient = new ApiClient();
