  1→/**
  2→ * Main Content -- layout orchestrator.
  3→ *
  4→ * Two-panel horizontal split (40/60 default ratio):
  5→ *   SESSION PANEL (left, 40%):  WorkspaceHeader → SessionTabs → Chat → Input
  6→ *   CONTENT PANEL (right, 60%): ContentTabBar + PRActions → ContentArea
  7→ *
  8→ * Each panel has its own header bar. The split is the top-level layout.
  9→ * Content tab switching (Code, Config, Terminal, etc.) lives in the
 10→ * content panel's header. PR actions also live in the content panel header.
 11→ *
 12→ * Panel resizing uses react-resizable-panels for keyboard accessibility,
 13→ * touch support, and built-in collapse/expand with snap behavior.
 14→ *
 15→ * Concerns are split across extracted hooks:
 16→ * - useWorkspaceActions: PR bridge, archive, retry, manifest tasks
 17→ * - useKeyboardShortcuts: Cmd+\ toggles session panel
 18→ */
 19→
 20→import { useRef, useCallback, useMemo, useEffect } from "react";
 21→import type { ImperativePanelHandle } from "react-resizable-panels";
 22→import type { SessionPanelRef } from "@/features/session";
 23→import { WelcomeView } from "@/features/repository";
 24→import { useWorkspaceLayout } from "@/features/workspace";
 25→import { useCollapsedSizePercent } from "@/features/workspace/hooks/useCollapsedSizePercent";
 26→import type { RightSideTab } from "@/features/workspace/store";
 27→import { useFileWatcher } from "@/features/file-browser/hooks/useFileWatcher";
 28→import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
 29→import { ContentTabBar, isTabVisible } from "@/features/workspace/ui/ContentTabBar";
 30→import { PRActions } from "@/features/workspace/ui/PRActions";
 31→import { useSettings } from "@/features/settings/api/settings.queries";
 32→import { SidebarInset, useSidebar } from "@/components/ui";
 33→import { cn } from "@/shared/lib/utils";
 34→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 35→import { PanelLeft } from "lucide-react";
 36→import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
 37→import { useUpdateWorkspaceStatus } from "@/features/workspace/api";
 38→import { REVIEW_CODE } from "@/features/session/lib/sessionPrompts";
 39→import { native } from "@/platform";
 40→import { BROWSER_WORKSPACE_CHANGE } from "@shared/events";
 41→import { useBrowserWindowStore } from "@/features/browser/store";
 42→import { track } from "@/platform/analytics";
 43→import { ChatArea } from "./ChatArea";
 44→import { RightSidePanel } from "./RightSidePanel";
 45→import { CollapsedChatStrip, CollapsedContentStrip } from "./CollapsedPanelStrips";
 46→import { useWorkspaceActions } from "./hooks/useWorkspaceActions";
 47→import { usePanelShortcuts } from "./hooks/usePanelShortcuts";
 48→
 49→interface MainContentProps {
 50→  selectedWorkspace: Workspace | null;
 51→  prStatus: PRStatus | null;
 52→  ghStatus?: GhCliStatus | null;
 53→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 54→  onCreateWorkspace: () => void;
 55→  onOpenProject: () => void;
 56→  onCloneRepository: () => void;
 57→}
 58→
 59→export function MainContent({
 60→  selectedWorkspace,
 61→  prStatus,
 62→  ghStatus,
 63→  workspaceChatPanelRef,
 64→  onCreateWorkspace,
 65→  onOpenProject,
 66→  onCloneRepository,
 67→}: MainContentProps) {
 68→  const { open: sidebarOpen, toggleSidebar } = useSidebar();
 69→
 70→  const selectedWorkspaceId = selectedWorkspace?.id ?? null;
 71→  const {
 72→    rightSideTab,
 73→    setRightSideTab,
 74→    chatPanelCollapsed,
 75→    setChatPanelCollapsed,
 76→    rightPanelCollapsed,
 77→    setRightPanelCollapsed,
 78→  } = useWorkspaceLayout(selectedWorkspaceId);
 79→
 80→  // Effective tab: if the stored tab is hidden by experimental settings, fall back to "code".
 81→  const experimentalSettings = useSettings().data;
 82→  const effectiveRightSideTab = isTabVisible(rightSideTab, experimentalSettings)
 83→    ? rightSideTab
 84→    : "code";
 85→
 86→  const isBrowserDetached = useBrowserWindowStore((s) => s.detachedWindowOpen);
 87→
 88→  // --- Workspace actions (PR bridge, archive, retry, manifest) ---
 89→  const {
 90→    createPRHandler,
 91→    setCreatePRHandler,
 92→    sendAgentMessageHandler,
 93→    setSendAgentMessageHandler,
 94→    selectedTargetBranch,
 95→    setSelectedTargetBranch,
 96→    handleCreatePR,
 97→    handleSendAgentMessage,
 98→    handleArchive,
 99→    handleRetrySetup,
100→    handleViewSetupLogs,
101→    manifestTasks,
102→    hasManifest,
103→    handleRunTask,
104→  } = useWorkspaceActions({
105→    selectedWorkspace,
106→    setRightSideTab,
107→  });
108→
109→  const statusMutation = useUpdateWorkspaceStatus();
110→
111→  // Only start watching and querying diffs once the worktree checkout is complete.
112→  const isReady = selectedWorkspace?.state === "ready";
113→
114→  // Watch workspace for file changes (event-driven cache invalidation)
115→  const isWatched = useFileWatcher(
116→    isReady ? (selectedWorkspace?.workspace_path ?? null) : null,
117→    isReady ? selectedWorkspaceId : null
118→  );
119→
120→  // --- Refs for imperative panel control ---
121→  const chatPanelRef = useRef<ImperativePanelHandle>(null);
122→  const contentPanelRef = useRef<ImperativePanelHandle>(null);
123→  const panelGroupContainerRef = useRef<HTMLDivElement>(null);
124→
125→  // Dynamic collapsed size: 36px strip -> percentage of container width.
126→  const MIN_PANEL_SIZE = 15;
127→  const collapsedSizePct = useCollapsedSizePercent(panelGroupContainerRef, 36);
128→  const safeCollapsedSize = Math.min(collapsedSizePct, MIN_PANEL_SIZE - 0.1);
129→
130→  // Default split: 40% session / 60% content — same for all tabs.
131→  const sessionPanelDefaultSize = 40;
132→  const contentPanelDefaultSize = 60;
133→
134→  const sessionStatus = selectedWorkspace?.session_status;
135→  const isSessionWorking = sessionStatus === "working";
136→
137→  // --- Content tab change ---
138→  const handleContentTabChange = useCallback(
139→    (tab: RightSideTab) => {
140→      setRightSideTab(tab);
141→      // Track feature surface adoption — fire on every user-initiated tab switch.
142→      // We use a static map instead of ts-pattern here because these are all
143→      // simple string→event mappings with no branching logic.
144→      const tabEventMap: Partial<Record<RightSideTab, () => void>> = {
145→        terminal: () =>
146→          track("terminal_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
147→        browser: () => track("browser_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
148→        simulator: () =>
149→          track("simulator_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
150→        code: () => track("diff_viewed", { workspace_id: selectedWorkspaceId ?? undefined }),
151→      };
152→      tabEventMap[tab]?.();
153→    },
154→    [setRightSideTab, selectedWorkspaceId]
155→  );
156→
157→  // --- Chat panel collapse/expand ---
158→  const handleCollapseChatPanel = useCallback(() => {
159→    setChatPanelCollapsed(true);
160→    chatPanelRef.current?.collapse();
161→  }, [setChatPanelCollapsed]);
162→
163→  const handleExpandChatPanel = useCallback(() => {
164→    setChatPanelCollapsed(false);
165→  }, [setChatPanelCollapsed]);
166→
167→  // --- Content panel collapse/expand ---
168→  const handleCollapseContentPanel = useCallback(() => {
169→    setRightPanelCollapsed(true);
170→    contentPanelRef.current?.collapse();
171→  }, [setRightPanelCollapsed]);
172→
173→  const handleExpandContentPanel = useCallback(() => {
174→    setRightPanelCollapsed(false);
175→  }, [setRightPanelCollapsed]);
176→
177→  // --- Keyboard shortcuts ---
178→  usePanelShortcuts({
179→    enabled: selectedWorkspace !== null,
180→    chatPanelCollapsed,
181→    chatPanelRef,
182→    contentPanelCollapsed: rightPanelCollapsed,
183→    contentPanelRef,
184→  });
185→
186→  // --- Reset panel sizes on workspace switch ---
187→  // ResizablePanelGroup has no key prop — it stays mounted across workspace
188→  // switches so SimulatorPanel and BrowserPanel keep their native sessions alive.
189→  // Without the key, react-resizable-panels won't re-apply defaultSize on
190→  // re-render. We must imperatively collapse/expand panels to match the
191→  // per-workspace Zustand state when the selected workspace changes.
192→  useEffect(() => {
193→    if (!selectedWorkspaceId) return;
194→    if (chatPanelCollapsed) {
195→      chatPanelRef.current?.collapse();
196→    } else {
197→      chatPanelRef.current?.expand();
198→      chatPanelRef.current?.resize(sessionPanelDefaultSize);
199→    }
200→    if (rightPanelCollapsed) {
201→      contentPanelRef.current?.collapse();
202→    } else {
203→      contentPanelRef.current?.expand();
204→      contentPanelRef.current?.resize(contentPanelDefaultSize);
205→    }
206→    // eslint-disable-next-line react-hooks/exhaustive-deps -- only fire on workspace change, not on collapse toggles
207→  }, [selectedWorkspaceId]);
208→
209→  // --- Hide all native BrowserViews on workspace switch ---
210→  // BrowserViews are native Electron overlays rendered ABOVE the DOM. When
211→  // switching workspaces or going to the welcome screen, stale views from
212→  // the previous workspace would remain visible. Hide them immediately;
213→  // the new workspace's BrowserTab will re-show its own view when ready.
214→  useEffect(() => {
215→    native.browserViews.hideAll().catch(() => {});
216→  }, [selectedWorkspaceId]);
217→
218→  // --- Sync workspace changes to detached browser window ---
219→  const detachedWorkspaceContext = useMemo(
220→    () =>
221→      selectedWorkspace
222→        ? {
223→            workspaceId: selectedWorkspace.id,
224→            directoryName: selectedWorkspace.slug,
225→            repoName: selectedWorkspace.repo_name,
226→            branch: selectedWorkspace.git_branch,
227→          }
228→        : null,
229→    [selectedWorkspace]
230→  );
231→
232→  useEffect(() => {
233→    if (!isBrowserDetached || !detachedWorkspaceContext) return;
234→    void native.events.send(BROWSER_WORKSPACE_CHANGE, detachedWorkspaceContext);
235→  }, [isBrowserDetached, detachedWorkspaceContext]);
236→
237→  // Switching to code tab — used by file clicks (diff or preview) in RightSidePanel.
238→  const handleSwitchToCodeTab = useCallback(() => {
239→    setRightSideTab("code");
240→  }, [setRightSideTab]);
241→
242→  // Insert code review prompt into chat input
243→  const handleInsertReviewPrompt = useCallback(() => {
244→    workspaceChatPanelRef.current?.insertText(REVIEW_CODE);
245→  }, [workspaceChatPanelRef]);
246→
247→  return (
248→    <SidebarInset className="min-w-0">
249→      <div
250→        data-slot="main-content"
251→        className={cn(
252→          "bg-bg-surface flex h-full min-w-0 flex-1 overflow-hidden border transition-[border-radius,border-color] duration-[280ms] ease-[cubic-bezier(.19,1,.22,1)]",
253→          sidebarOpen
254→            ? "border-border-subtle rounded-l-xl border-r-0"
255→            : "rounded-none border-transparent"
256→        )}
257→      >
258→        {/* Sidebar toggle -- visible when sidebar collapsed and no workspace */}
259→        {!sidebarOpen && !selectedWorkspace && (
260→          <button
261→            type="button"
262→            data-slot="welcome-sidebar-toggle"
263→            aria-label="Expand sidebar"
264→            onClick={toggleSidebar}
265→            className="text-muted-foreground/60 hover:text-foreground hover:bg-foreground/5 absolute top-3 left-3 z-10 flex h-7 w-7 items-center justify-center rounded-lg transition-[transform,color,background-color] duration-200 ease-out"
266→          >
267→            <PanelLeft className="h-4 w-4" />
268→          </button>
269→        )}
270→
271→        {selectedWorkspace ? (
272→          /* Two-panel split — the top-level layout, no full-width header */
273→          <div ref={panelGroupContainerRef} className="min-h-0 min-w-0 flex-1">
274→            <ResizablePanelGroup direction="horizontal">
275→              {/* ─── SESSION PANEL (left, collapsible) ─── */}
276→              <ResizablePanel
277→                ref={chatPanelRef}
278→                collapsible
279→                collapsedSize={safeCollapsedSize}
280→                minSize={MIN_PANEL_SIZE}
281→                defaultSize={chatPanelCollapsed ? safeCollapsedSize : sessionPanelDefaultSize}
282→                onCollapse={handleCollapseChatPanel}
283→                onExpand={handleExpandChatPanel}
284→                className="min-w-0"
285→                order={1}
286→              >
287→                {chatPanelCollapsed ? (
288→                  <CollapsedChatStrip
289→                    onExpand={() => chatPanelRef.current?.expand()}
290→                    isWorking={isSessionWorking}
291→                  />
292→                ) : (
293→                  <div className="flex h-full min-w-0 flex-col">
294→                    {/* Title header — workspace name + repo/branch + Open */}
295→                    <WorkspaceHeader
296→                      title={selectedWorkspace.title ?? undefined}
297→                      repositoryName={selectedWorkspace.repo_name}
298→                      branch={selectedWorkspace.git_branch ?? undefined}
299→                      workspacePath={selectedWorkspace.workspace_path}
300→                      setupStatus={selectedWorkspace.setup_status}
301→                      setupError={selectedWorkspace.error_message}
302→                      onSendAgentMessage={
303→                        sendAgentMessageHandler ? handleSendAgentMessage : undefined
304→                      }
305→                      onRetrySetup={
306→                        selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
307→                      }
308→                      onViewSetupLogs={
309→                        selectedWorkspace.setup_status === "failed"
310→                          ? handleViewSetupLogs
311→                          : undefined
312→                      }
313→                      workspaceStatus={selectedWorkspace.status}
314→                      onStatusChange={(status) =>
315→                        statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
316→                      }
317→                      tasks={manifestTasks}
318→                      hasManifest={hasManifest}
319→                      onRunTask={handleRunTask}
320→                    />
321→
322→                    {/* Session tabs + chat messages + input */}
323→                    <ChatArea
324→                      key={selectedWorkspace.id}
325→                      workspace={selectedWorkspace}
326→                      workspaceChatPanelRef={workspaceChatPanelRef}
327→                      onCreatePRHandlerChange={setCreatePRHandler}
328→                      onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
329→                      onCollapseChatPanel={handleCollapseChatPanel}
330→                    />
331→                  </div>
332→                )}
333→              </ResizablePanel>
334→
335→              <ResizableHandle />
336→
337→              {/* ─── CONTENT PANEL (right, collapsible) ─── */}
338→              <ResizablePanel
339→                ref={contentPanelRef}
340→                collapsible
341→                collapsedSize={safeCollapsedSize}
342→                defaultSize={rightPanelCollapsed ? safeCollapsedSize : contentPanelDefaultSize}
343→                minSize={MIN_PANEL_SIZE}
344→                onCollapse={handleCollapseContentPanel}
345→                onExpand={handleExpandContentPanel}
346→                className="min-w-0"
347→                order={2}
348→              >
349→                {rightPanelCollapsed ? (
350→                  <CollapsedContentStrip onExpand={() => contentPanelRef.current?.expand()} />
351→                ) : (
352→                  <div className="flex h-full flex-col pr-2 pb-2">
353→                    {/* Tab header: content tabs (left) + PR actions (right) */}
354→                    <div className="drag-region flex h-11 flex-shrink-0 items-center justify-between px-2.5">
355→                      <ContentTabBar
356→                        activeTab={effectiveRightSideTab}
357→                        onTabChange={handleContentTabChange}
358→                        workspaceId={selectedWorkspaceId}
359→                      />
360→                      <PRActions
361→                        prStatus={prStatus}
362→                        ghStatus={ghStatus}
363→                        onCreatePR={createPRHandler ? handleCreatePR : undefined}
364→                        onSendAgentMessage={
365→                          sendAgentMessageHandler ? handleSendAgentMessage : undefined
366→                        }
367→                        onArchive={handleArchive}
368→                        targetBranch={selectedTargetBranch}
369→                        onTargetBranchChange={setSelectedTargetBranch}
370→                        workspacePath={selectedWorkspace.workspace_path}
371→                        workspaceId={selectedWorkspaceId ?? undefined}
372→                      />
373→                    </div>
374→
375→                    {/* Content area — rounded corners, subtle border */}
376→                    <div className="border-border-subtle bg-bg-elevated flex min-h-0 flex-1 overflow-hidden rounded-lg border">
377→                      <RightSidePanel
378→                        workspace={selectedWorkspace}
379→                        activeTab={effectiveRightSideTab}
380→                        onSwitchToCodeTab={handleSwitchToCodeTab}
381→                        isWatched={isWatched}
382→                        onReview={handleInsertReviewPrompt}
383→                      />
384→                    </div>
385→                  </div>
386→                )}
387→              </ResizablePanel>
388→            </ResizablePanelGroup>
389→          </div>
390→        ) : (
391→          <div className="flex min-w-0 flex-1">
392→            <WelcomeView
393→              onCreateWorkspace={onCreateWorkspace}
394→              onOpenProject={onOpenProject}
395→              onCloneRepository={onCloneRepository}
396→            />
397→          </div>
398→        )}
399→      </div>
400→    </SidebarInset>
401→  );
402→}
403→

