 81→export function MainLayout() {
 82→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 83→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 84→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 85→
 86→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
 87→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
 88→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
 89→  const settingsOpen = useUIStore((s) => s.settingsOpen);
 90→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
 91→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
 92→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
 93→
 94→  // TanStack Query
 95→  const workspacesQuery = useWorkspacesByRepo();
 96→
 97→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
 98→  const loading = workspacesQuery.isLoading;
 99→
100→  // Derive the full workspace object from React Query data.
101→  // The store only holds an ID; this useMemo resolves it to a Workspace
102→  // on every React Query refresh, eliminating the old sync effect entirely.
103→  const selectedWorkspace = useMemo(() => {
104→    if (!selectedWorkspaceId || !repoGroups.length) return null;
105→    for (const group of repoGroups) {
106→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
107→      if (found) return found;
108→    }
109→    return null;
110→  }, [selectedWorkspaceId, repoGroups]);
111→
112→  const selectedWorkspaceIdRef = useRef(selectedWorkspaceId);
113→  useEffect(() => {
114→    selectedWorkspaceIdRef.current = selectedWorkspaceId;
115→  });
116→
117→  // Bulk-fetch diff stats for all workspaces (replaces per-item useDiffStats in sidebar)
118→  const bulkDiffStatsQuery = useBulkDiffStats(repoGroups);
119→
120→  // Sidebar resize: null = default 344px, number = user-set width
121→  const [sidebarWidth, setSidebarWidth] = useState<number | null>(null);
122→  // Tracks drag state to disable sidebar CSS transitions during resize
