130→
131→  // Queries for repos, settings
132→  const reposQuery = useRepos();
133→  const settingsQuery = useSettingsQuery();
134→
135→  const repos = reposQuery.data || [];
136→  const username = settingsQuery.data?.user_name || "My Account";
137→
138→  // GitHub CLI status — gates PR polling (like Codex)
139→  const ghStatusQuery = useGhStatus();
140→
141→  // PR status query — gated on gh CLI, polls while agent is working
142→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
143→    ghInstalled: ghStatusQuery.data?.isInstalled,
144→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
145→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
146→  });
147→
148→  // --- Extracted hooks ---
149→
150→  const repoActions = useRepoActions({
151→    selectWorkspace,
152→    openNewWorkspaceModal,
153→    closeNewWorkspaceModal,
154→  });
155→
156→  // Derive repo name for GitHub picker modal from repoGroups
157→  const githubPickerRepoName = useMemo(() => {
158→    if (!githubPickerRepoId) return "";
159→    const group = repoGroups.find((g) => g.repo_id === githubPickerRepoId);
160→    return group?.repo_name ?? "";
161→  }, [githubPickerRepoId, repoGroups]);
162→
163→  // Hide native WebContentsViews when any dialog is open — they render above
164→  // the DOM so dialogs would appear behind them. BrowserTab's own visible
165→  // effect handles re-showing when the dialog closes.
166→  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
167→  const anyDialogOpen =
168→    showNewWorkspaceModal ||
169→    showSystemPromptModal ||
170→    commandPaletteOpen ||
171→    !!githubPickerRepoId ||
172→    repoActions.showCloneModal;
173→  useEffect(() => {
174→    if (anyDialogOpen) {
