179→  // --- System prompt (inline — small scope, one modal) ---
180→
181→  const systemPromptQuery = useSystemPrompt(selectedWorkspace?.id || null);
182→  const updateSystemPromptMutation = useUpdateSystemPrompt();
183→  // Track user edits separately; reset to null when modal closes so the
184→  // derived value from the query takes over again (no useEffect + setState).
185→  const [systemPromptEdit, setSystemPromptEdit] = useState<string | null>(null);
186→  const systemPromptDraft = systemPromptEdit ?? (systemPromptQuery.data || "");
187→  const setSystemPromptDraft = useCallback((value: string) => setSystemPromptEdit(value), []);
188→
189→  async function saveSystemPrompt() {
190→    if (!selectedWorkspace) return;
191→    try {
192→      await updateSystemPromptMutation.mutateAsync({
193→        workspaceId: selectedWorkspace.id,
194→        systemPrompt: systemPromptDraft,
195→      });
196→      closeSystemPromptModal();
197→      setSystemPromptEdit(null);
198→    } catch (error) {
199→      console.error("Failed to save system prompt:", error);
200→      toast.error(getErrorMessage(error));
201→    }
202→  }
203→
204→  // --- Archive with undo (ref-stable for memoized sidebar items) ---
205→
206→  const archiveWorkspaceMutation = useArchiveWorkspace();
207→  const unarchiveMutation = useUnarchiveWorkspace();
208→
209→  // Ref-stable archive handler: archiveWorkspaceMutation and selectedWorkspace
210→  // change frequently (every render / every workspace click), so we capture
211→  // them in refs to keep the callback identity stable. This matters because
212→  // onArchive flows through the entire sidebar tree to every memoized WorkspaceItem.
213→  const archiveMutationRef = useRef(archiveWorkspaceMutation);
214→  const unarchiveMutationRef = useRef(unarchiveMutation);
215→  const selectedWorkspaceRef = useRef(selectedWorkspace);
216→  useEffect(() => {
217→    archiveMutationRef.current = archiveWorkspaceMutation;
218→    unarchiveMutationRef.current = unarchiveMutation;
219→    selectedWorkspaceRef.current = selectedWorkspace;
220→  });
221→
222→  const archiveWorkspace = useCallback(
223→    async (workspaceId: string) => {
224→      try {
225→        await archiveMutationRef.current.mutateAsync(workspaceId);
226→        if (selectedWorkspaceRef.current?.id === workspaceId) {
227→          selectWorkspace(null);
228→        }
229→        toast("Workspace archived", {
230→          duration: 5000,
231→          action: {
232→            label: "Undo",
233→            onClick: () => {
234→              unarchiveMutationRef.current.mutateAsync(workspaceId).catch((error) => {
235→                toast.error(getErrorMessage(error));
236→              });
237→            },
238→          },
239→        });
240→      } catch (error) {
241→        console.error("Error archiving workspace:", error);
242→        toast.error(getErrorMessage(error));
243→      }
244→    },
245→    [selectWorkspace]
246→  );
247→
248→  // --- Workflow status change (ref-stable like archive) ---
249→
250→  const statusMutation = useUpdateWorkspaceStatus();
251→  const statusMutationRef = useRef(statusMutation);
252→  useEffect(() => {
253→    statusMutationRef.current = statusMutation;
254→  });
255→
256→  const handleStatusChange = useCallback(
257→    (workspaceId: string, status: import("@shared/enums").WorkspaceStatus) => {
258→      statusMutationRef.current.mutate(
259→        { workspaceId, status },
260→        { onError: (error) => toast.error(getErrorMessage(error)) }
261→      );
262→    },
263→    []
264→  );
265→
266→  // --- Global hooks ---
267→
268→  // Zoom (Cmd+=/Cmd+-/Cmd+0)
269→  useZoom();
270→
271→  // Track fullscreen state — toggles `.fullscreen` class on <html> for CSS
272→  useIsFullscreen();
273→
274→  // Adds .electron class to <html> and injects CSS-only drag region rules.
275→  // Headers with .drag-region class become draggable; buttons auto-excluded.
276→  useWindowDragZone();
277→
278→  // Disable CSS transitions during native window resize to prevent content "sticking"
279→  useWindowResizing();
280→
281→  // Keyboard shortcuts
282→  useKeyboardShortcuts({
283→    onRefresh: async () => {
284→      workspacesQuery.refetch();
285→      if (selectedWorkspace) {
286→        prStatusQuery.refetch();
287→      }
288→    },
289→    onEscape: () => {
290→      if (showNewWorkspaceModal) {
291→        closeNewWorkspaceModal();
292→      } else if (showSystemPromptModal) {
293→        closeSystemPromptModal();
294→      }
295→    },
296→    selectedWorkspace,
297→    modalStates: {
298→      showNewWorkspaceModal,
299→      showSystemPromptModal,
300→    },
301→  });
302→
303→  // Subscribe to chatInsertStore for content dispatched from BrowserPanel / DiffViewer / SimulatorPanel
304→  useEffect(() => {
305→    const unsubStore = useChatInsertStore.subscribe((state, prevState) => {
306→      if (!state.pending || state.pending === prevState.pending) return;
307→
308→      const payload = state.pending;
309→      chatInsertActions.consume();
310→
311→      if (!workspaceChatPanelRef.current) return;
312→      if (!isChatInsertForWorkspace(payload, selectedWorkspaceIdRef.current)) return;
313→
314→      deliverChatInsertPayload(workspaceChatPanelRef.current, payload);
315→    });
316→
317→    const unlistenChat = native.events.on(CHAT_INSERT, (data) => {
318→      void deserializeChatInsertPayload(data)
319→        .then((payload) => {
320→          chatInsertActions.dispatch(payload);
321→        })
322→        .catch((error) => {
323→          console.error("Failed to deserialize detached chat insert:", error);
324→        });
325→    });
326→
327→    return () => {
328→      unsubStore();
329→      unlistenChat();
330→    };
331→  }, []);
332→
333→  const handleWorkspaceClick = useCallback(
334→    (workspace: Workspace) => {
335→      selectWorkspace(workspace.id);
336→    },
337→    [selectWorkspace]
338→  );
339→
340→  return (
341→    <SidebarProvider
342→      className="h-full"
343→      data-resizing={sidebarDragging || undefined}
344→      style={
345→        {
346→          "--sidebar-width": sidebarWidth ? `${sidebarWidth}px` : "344px",
347→          "--sidebar-width-mobile": "344px",
348→        } as React.CSSProperties
349→      }
350→    >
351→      {/* Sidebar — swap between app sidebar and settings sidebar */}
352→      {settingsOpen ? (
353→        <SettingsSidebar />
354→      ) : loading ? (
355→        <SidebarSkeleton />
356→      ) : (
357→        <AppSidebar
358→          repositories={repoGroups}
359→          selectedWorkspaceId={selectedWorkspace?.id || null}
360→          diffStatsMap={bulkDiffStatsQuery.data}
361→          onWorkspaceClick={handleWorkspaceClick}
362→          onNewWorkspace={repoActions.handleNewWorkspace}
363→          onNewWorkspaceFromGitHub={setGithubPickerRepoId}
364→          onAddRepository={repoActions.handleOpenProject}
365→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
366→          onArchive={archiveWorkspace}
367→          onStatusChange={handleStatusChange}
368→          profile={{ username }}
369→        />
370→      )}
371→
372→      {/* Sidebar resize handle */}
373→      <SidebarResizeHandle onSizeChange={setSidebarWidth} onDraggingChange={setSidebarDragging} />
374→
375→      {/* Main Content — swap between app content and settings page */}
376→      {settingsOpen ? (
377→        <SettingsPage />
378→      ) : (
379→        <MainContent
380→          selectedWorkspace={selectedWorkspace}
381→          prStatus={prStatusQuery.data ?? null}
382→          ghStatus={ghStatusQuery.data}
383→          workspaceChatPanelRef={workspaceChatPanelRef}
384→          onCreateWorkspace={openNewWorkspaceModal}
385→          onOpenProject={repoActions.handleOpenProject}
386→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
387→        />
388→      )}
389→
390→      {/* Modals */}
391→      <NewWorkspaceModal
392→        show={showNewWorkspaceModal}
393→        repos={repos}
394→        selectedRepoId={repoActions.selectedRepoId}
395→        creating={repoActions.creating}
396→        onClose={closeNewWorkspaceModal}
397→        onRepoChange={repoActions.setSelectedRepoId}
398→        onCreate={
399→          newWorkspaceMode === "from-github"
400→            ? () => {
401→                const repoId = repoActions.selectedRepoId;
402→                closeNewWorkspaceModal();
403→                if (repoId) setGithubPickerRepoId(repoId);
404→              }
405→            : repoActions.createWorkspaceFromModal
406→        }
407→        mode={newWorkspaceMode}
408→      />
409→
410→      <SystemPromptModal
411→        show={showSystemPromptModal && !!selectedWorkspace}
412→        workspaceName={selectedWorkspace?.slug || ""}
413→        systemPrompt={systemPromptDraft}
414→        loading={systemPromptQuery.isLoading}
415→        saving={updateSystemPromptMutation.isPending}
416→        onClose={() => {
417→          closeSystemPromptModal();
418→          setSystemPromptEdit(null);
419→        }}
420→        onChange={setSystemPromptDraft}
421→        onSave={saveSystemPrompt}
422→      />
423→
424→      <CloneRepositoryModal
425→        show={repoActions.showCloneModal}
426→        cloning={repoActions.cloning}
427→        error={repoActions.cloneError}
428→        statusMessage={repoActions.cloneStatus}
429→        onClose={repoActions.closeCloneModal}
430→        onClone={repoActions.handleCloneRepository}
431→        onClearError={repoActions.clearCloneError}
432→      />
433→
434→      <GitHubPickerModal
435→        open={!!githubPickerRepoId}
436→        onOpenChange={(open) => !open && setGithubPickerRepoId(null)}
437→        repoId={githubPickerRepoId || ""}
438→        repoName={githubPickerRepoName}
439→        onCreateWorkspace={repoActions.handleNewWorkspaceFromGitHub}
440→      />
441→
442→      {/* Command Palette (Cmd+K) */}
443→      <CommandPalette
444→        actionOverrides={{
445→          "open-project": repoActions.handleOpenProject,
446→          "clone-repository": () => repoActions.setShowCloneModal(true),
447→        }}
448→      />
449→    </SidebarProvider>
450→  );
451→}
