 1→/**
 2→ * Connects the WebSocket query protocol client on app mount.
 3→ *
 4→ * All reactive data delivery happens through q:snapshot and q:delta pushed
 5→ * to active WS subscriptions — no separate invalidation bridge is needed.
 6→ *
 7→ * Accepts an optional serverId for relay mode (web-production) where the
 8→ * WS URL includes the server ID in the path.
 9→ */
10→
11→import { useEffect, useRef } from "react";
12→import { connect, forceReconnect } from "@/platform/ws";
13→
14→export function useQueryProtocol(serverId?: string): void {
15→  // Track the previous serverId so we can detect changes vs initial mount
16→  const prevServerIdRef = useRef<string | undefined>(serverId);
17→
18→  // Connect the WS client once on mount (or when serverId changes)
19→  useEffect(() => {
20→    // If serverId changed (not initial mount), force the singleton WS client
21→    // to reconnect so it picks up the new relay endpoint URL.
22→    if (prevServerIdRef.current !== undefined && prevServerIdRef.current !== serverId) {
23→      forceReconnect();
24→    }
25→    prevServerIdRef.current = serverId;
26→
27→    connect(serverId).catch((err) => {
28→      // Non-fatal: WS is additive. HTTP + IPC events still work.
29→      if (import.meta.env.DEV) {
30→        console.warn("[QueryProtocol] WS connection failed:", err);
31→      }
32→    });
33→
34→    return () => {
35→      // On serverId change the effect re-runs — the forceReconnect() above
36→      // handles reconnection. On final unmount (no new serverId), the WS
37→      // stays open for potential reuse by other consumers.
38→    };
39→  }, [serverId]);
40→}
