426→  const [pageState, setPageState] = useState<PageState>(isAutoConnect ? "connecting" : "idle");
427→
428→  const autoSubmitTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
429→  const successTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
430→  const reduced = useReducedMotion();
431→
432→  // Clean up all timers on unmount
433→  useEffect(() => {
434→    return () => {
435→      if (autoSubmitTimer.current) clearTimeout(autoSubmitTimer.current);
436→      if (successTimer.current) clearTimeout(successTimer.current);
437→    };
438→  }, []);
439→
440→  const submitCode = useCallback(
441→    async (rawCode: string) => {
442→      const normalized = normalizeCode(rawCode);
443→      if (!normalized) return;
444→
445→      setError(null);
446→      setPageState("connecting");
447→
448→      const deviceName = navigator.userAgent.includes("Mobile") ? "Mobile Browser" : "Web Browser";
449→
450→      try {
451→        let token: string;
452→        let resolvedName: string | undefined = deviceName;
453→
454→        if (isRelayMode()) {
455→          const resolvedServerId = serverId || getServerIdFromUrl();
456→          if (!resolvedServerId) {
457→            setError("Unable to connect. Try opening the link from your desktop app again.");
458→            setPageState("error");
459→            return;
460→          }
461→          const result = await pairViaRelay(resolvedServerId, normalized, deviceName);
462→          token = result.token;
463→        } else {
464→          const data = await pairViaDirect(normalized, deviceName);
465→          token = data.token;
466→          resolvedName = data.device?.name;
467→        }
468→
469→        // Show success state, then navigate
470→        setPageState("success");
471→        if (successTimer.current) clearTimeout(successTimer.current);
472→        successTimer.current = setTimeout(() => onPaired(token, resolvedName), SUCCESS_HOLD_MS);
473→      } catch (err) {
474→        setError(err instanceof Error ? err.message : "Unable to connect. Try again.");
475→        setPageState("error");
476→      }
477→    },
478→    [onPaired, serverId]
479→  );
480→
481→  // Auto-submit on mount if code came from URL
482→  useEffect(() => {
483→    if (prefill) {
484→      submitCode(prefill);
485→    }
486→    // eslint-disable-next-line react-hooks/exhaustive-deps
487→  }, []);
488→
489→  function clearAutoSubmitTimer() {
490→    if (autoSubmitTimer.current) {
491→      clearTimeout(autoSubmitTimer.current);
492→      autoSubmitTimer.current = null;
493→    }
494→  }
495→
496→  function handleSubmit(e: React.FormEvent) {
497→    e.preventDefault();
498→    clearAutoSubmitTimer();
499→    submitCode(code);
500→  }
501→
502→  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
503→    clearAutoSubmitTimer();
504→    setCode(e.target.value.toUpperCase());
505→    setError(null);
506→  }
507→
508→  function handlePaste(e: React.ClipboardEvent<HTMLInputElement>) {
509→    const pasted = e.clipboardData.getData("text");
510→    const resolved = extractCodeFromPastedUrl(pasted) ?? normalizeCode(pasted);
511→    if (!resolved) return;
512→
513→    e.preventDefault();
514→    setCode(resolved);
515→    setError(null);
516→
517→    clearAutoSubmitTimer();
518→    autoSubmitTimer.current = setTimeout(() => submitCode(resolved), 300);
519→  }
520→
521→  function handleRetryAutoConnect() {
522→    if (prefill) {
523→      submitCode(prefill);
524→    } else {
525→      setPageState("idle");
526→      setError(null);
527→    }
528→  }
529→
530→  const codeIsValid = normalizeCode(code) !== null;
531→
532→  function renderContent() {
533→    if (isAutoConnect && pageState === "connecting") {
534→      return <ConnectingView reduced={reduced} />;
535→    }
536→
537→    if (pageState === "success") {
538→      return <SuccessView reduced={reduced} />;
539→    }
540→
541→    if (isAutoConnect && pageState === "error") {
542→      return (
543→        <AutoConnectErrorView
544→          error={error ?? "Unable to connect."}
545→          onRetry={handleRetryAutoConnect}
546→        />
547→      );
548→    }
549→
550→    return (
551→      <ManualEntryView
552→        code={code}
553→        error={pageState === "error" ? error : null}
554→        isPending={pageState === "connecting"}
555→        codeIsValid={codeIsValid}
556→        reduced={reduced}
557→        onChange={handleChange}
558→        onPaste={handlePaste}
559→        onSubmit={handleSubmit}
560→      />
561→    );
562→  }
563→
564→  return (
565→    <div className="bg-background flex min-h-screen items-center justify-center p-4">
566→      <AnimatePresence mode="wait">{renderContent()}</AnimatePresence>
567→    </div>
568→  );
569→}
