  1→/**
  2→ * AIStatusIndicator — ambient AI provider health indicator for the sidebar footer.
  3→ *
  4→ * Renders nothing when all providers are operational (absence = healthy).
  5→ * Shows a colored dot + label when any provider has issues.
  6→ * Click opens a popover with per-provider breakdown + links to status pages.
  7→ */
  8→
  9→import { useState } from "react";
 10→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
 11→import { ArrowUpRight } from "lucide-react";
 12→import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
 13→import { cn } from "@/shared/lib/utils";
 14→import { useProviderStatuses, type ProviderStatusEntry } from "../api/ai-status.queries";
 15→import { PROVIDER_REGISTRY, getIndicatorVisuals } from "../lib/providers";
 16→
 17→const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
 18→
 19→export function AIStatusIndicator() {
 20→  const { statuses, worst } = useProviderStatuses();
 21→  const [open, setOpen] = useState(false);
 22→  const reduceMotion = useReducedMotion();
 23→
 24→  const visuals = worst ? getIndicatorVisuals(worst.indicator) : null;
 25→
 26→  // AnimatePresence must stay mounted for exit animations to fire
 27→  return (
 28→    <AnimatePresence>
 29→      {worst && visuals && (
 30→        <m.div
 31→          key="ai-status"
 32→          initial={reduceMotion ? false : { opacity: 0, scale: 0.8 }}
 33→          animate={{ opacity: 1, scale: 1 }}
 34→          exit={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.8 }}
 35→          transition={{ duration: reduceMotion ? 0 : 0.2, ease: EASE_OUT_QUART }}
 36→        >
 37→          <Popover open={open} onOpenChange={setOpen}>
 38→            <PopoverTrigger asChild>
 39→              <button
 40→                type="button"
 41→                aria-label={`AI provider status: ${visuals.label}`}
 42→                className="hover:bg-bg-muted flex items-center gap-1.5 rounded-lg px-1 py-0.5 transition-colors duration-150"
 43→              >
 44→                <StatusPulse dotClass={visuals.dotClass} pulse={worst.indicator === "critical"} />
 45→                <span className="text-text-muted text-xs">{visuals.label}</span>
 46→              </button>
 47→            </PopoverTrigger>
 48→
 49→            <PopoverContent side="top" align="end" className="w-72 p-3">
 50→              <StatusPopover statuses={statuses} />
 51→            </PopoverContent>
 52→          </Popover>
 53→        </m.div>
 54→      )}
 55→    </AnimatePresence>
 56→  );
 57→}
 58→
 59→function StatusPulse({ dotClass, pulse }: { dotClass: string; pulse: boolean }) {
 60→  return (
 61→    <span className="relative flex h-2 w-2 items-center justify-center">
 62→      {pulse && (
 63→        <span
 64→          className={cn(
 65→            "absolute inline-flex h-full w-full animate-ping rounded-full opacity-60",
 66→            dotClass
 67→          )}
 68→        />
 69→      )}
 70→      <span className={cn("relative inline-flex h-2 w-2 rounded-full", dotClass)} />
 71→    </span>
 72→  );
 73→}
 74→
 75→function StatusPopover({ statuses }: { statuses: ProviderStatusEntry[] }) {
 76→  return (
 77→    <div className="flex flex-col gap-2.5">
 78→      <p className="text-text-secondary text-xs font-medium">Provider Status</p>
 79→      {statuses.map((s) => {
 80→        const config = PROVIDER_REGISTRY[s.providerId];
 81→        if (!config) return null;
 82→        const visuals = getIndicatorVisuals(s.indicator);
 83→
 84→        return (
 85→          <div key={s.providerId} className="flex items-center justify-between gap-2">
 86→            <div className="flex min-w-0 items-center gap-2">
 87→              <span
 88→                className={cn(
 89→                  "h-1.5 w-1.5 shrink-0 rounded-full",
 90→                  s.isError ? "bg-text-muted" : visuals.dotClass
 91→                )}
 92→              />
 93→              <span className="text-text-primary truncate text-sm">{config.name}</span>
 94→            </div>
 95→            <a
 96→              href={config.statusPageUrl}
 97→              target="_blank"
 98→              rel="noopener noreferrer"
 99→              className="text-text-muted hover:text-text-secondary flex shrink-0 items-center gap-1 text-xs transition-colors duration-150"
100→            >
101→              {s.isError ? "Unavailable" : visuals.label}
102→              <ArrowUpRight className="h-3 w-3" />
103→            </a>
104→          </div>
105→        );
106→      })}
107→    </div>
108→  );
109→}
