 20→import { COMPACT_CONVERSATION, createPRPrompt } from "../lib/sessionPrompts";
 21→
 22→interface UseSessionActionsProps {
 23→  sessionId: string;
 24→  workspaceId?: string;
 25→  workspacePath: string;
 26→  messageInput: string;
 27→  model?: string;
 28→  agentType?: RuntimeAgentType;
 29→  onMessageSent?: () => void;
 30→  targetBranch?: string;
 31→}
 32→
 33→interface UseSessionActionsReturn {
 34→  // Actions
 35→  sendMessage: (customContent?: string) => Promise<void>;
 36→  stopSession: () => Promise<void>;
 37→  compactConversation: () => Promise<void>;
 38→  createPR: () => Promise<void>;
 39→
 40→  // Status
 41→  sending: boolean;
 42→}
 43→
 44→export function useSessionActions({
 45→  sessionId,
 46→  workspaceId,
 47→  workspacePath,
 48→  messageInput,
 49→  model,
 50→  agentType = "claude",
 51→  onMessageSent,
 52→  targetBranch = "main",
 53→}: UseSessionActionsProps): UseSessionActionsReturn {
 54→  const sendMessageMutation = useSendMessage();
 55→  const stopSessionMutation = useStopSession();
 56→
 57→  const sendMessage = useCallback(
 58→    async (customContent?: string) => {
 59→      const content = customContent || messageInput.trim();
 60→      if (!content || sendMessageMutation.isPending) return;
 61→
 62→      try {
 63→        // Single atomic call: sidecar saves message + starts agent.
 64→        // Optimistic UI fires in onMutate, rollback fires in onError.
 65→        await sendMessageMutation.mutateAsync({
 66→          sessionId,
 67→          content,
 68→          model,
 69→          cwd: workspacePath,
 70→          agentType,
 71→        });
 72→      } catch (error) {
 73→        console.error("Failed to send message:", error);
 74→        // onError already rolled back optimistic update.
 75→        // No stopSession cleanup needed — sidecar didn't persist anything on failure.
 76→        const reason = error instanceof Error ? error.message : "Failed to send message";
 77→        toast.error(reason);
 78→        return;
 79→      }
 80→
 81→      try {
 82→        onMessageSent?.();
 83→      } catch (callbackError) {
 84→        console.error("[useSessionActions] onMessageSent callback failed:", callbackError);
 85→      }
 86→    },
 87→    [messageInput, model, sendMessageMutation, sessionId, workspacePath, agentType, onMessageSent]
 88→  );
 89→
 90→  const stopSession = useCallback(async () => {
 91→    try {
 92→      // Cancel the sidecar agent first so it stops consuming API tokens
 93→      try {
 94→        if (!isConnected()) await connect();
 95→        await sendCommand("stopSession", { sessionId });
 96→      } catch (cancelError) {
 97→        console.error("[useSessionActions] Cancel query failed:", cancelError);
 98→      }
 99→      // Then update DB status to idle
100→      await stopSessionMutation.mutateAsync(sessionId);
101→    } catch (error) {
102→      console.error("Failed to stop session:", error);
103→    }
104→  }, [stopSessionMutation, sessionId, agentType]);
105→
106→  const compactConversation = useCallback(() => {
107→    return sendMessage(COMPACT_CONVERSATION);
108→  }, [sendMessage]);
109→
110→  const createPR = useCallback(() => {
111→    if (workspaceId) {
112→      track("pr_create_requested", { workspace_id: workspaceId, target_branch: targetBranch });
113→    }
114→    return sendMessage(createPRPrompt(targetBranch));
115→  }, [sendMessage, workspaceId, targetBranch]);
116→
117→  return {
118→    sendMessage,
119→    stopSession,
120→    compactConversation,
121→    createPR,
122→    sending: sendMessageMutation.isPending,
123→  };
124→}
