 1→/**
 2→ * Tiny event emitter for cross-feature connection signals.
 3→ *
 4→ * Session actions call emitSendAttemptFailed() when a command rejects
 5→ * because the WebSocket is down. The connection store listens and
 6→ * immediately escalates to DISCONNECTED state.
 7→ */
 8→
 9→type Listener = () => void;
10→
11→const listeners = new Set<Listener>();
12→
13→export function emitSendAttemptFailed(): void {
14→  for (const fn of listeners) fn();
15→}
16→
17→export function onSendAttemptFailed(cb: Listener): () => void {
18→  listeners.add(cb);
19→  return () => {
20→    listeners.delete(cb);
21→  };
22→}
