  1→/**
  2→ * Connection state machine — Zustand store.
  3→ *
  4→ * States:
  5→ *   CONNECTED     → healthy, all systems go
  6→ *   GRACE_PERIOD  → WS just dropped, wait 2s before showing anything
  7→ *   RECONNECTING  → 2-30s, show thin reconnecting bar
  8→ *   DISCONNECTED  → 30s+, show full banner, dim content
  9→ *
 10→ * Escalation shortcuts:
 11→ *   - If a sendCommand fails while in GRACE_PERIOD or RECONNECTING,
 12→ *     immediately jump to DISCONNECTED (user tried to act).
 13→ */
 14→
 15→import { create } from "zustand";
 16→import { forceReconnect } from "@/platform/ws";
 17→
 18→// --- Constants ---
 19→
 20→const GRACE_MS = 2_000;
 21→const ESCALATE_MS = 30_000;
 22→
 23→// --- Types ---
 24→
 25→export type ConnectionState = "connected" | "grace_period" | "reconnecting" | "disconnected";
 26→
 27→interface ConnectionStoreState {
 28→  state: ConnectionState;
 29→  disconnectedAt: number | null;
 30→  sendAttemptFailed: boolean;
 31→}
 32→
 33→interface ConnectionStoreActions {
 34→  /** Called by useConnectionStateInit when WS connects */
 35→  onConnected: () => void;
 36→  /** Called by useConnectionStateInit when WS disconnects */
 37→  onDisconnected: () => void;
 38→  /** Called when a user action (sendMessage) fails due to disconnection */
 39→  markSendAttemptFailed: () => void;
 40→  /** Force immediate reconnect attempt */
 41→  retry: () => void;
 42→  /** Internal: transition from grace to reconnecting */
 43→  _escalateToReconnecting: () => void;
 44→  /** Internal: transition from reconnecting to disconnected */
 45→  _escalateToDisconnected: () => void;
 46→}
 47→
 48→type ConnectionStore = ConnectionStoreState & ConnectionStoreActions;
 49→
 50→// --- Timer refs (module-level, not in store) ---
 51→
 52→let graceTimer: ReturnType<typeof setTimeout> | null = null;
 53→let escalateTimer: ReturnType<typeof setTimeout> | null = null;
 54→
 55→function clearTimers() {
 56→  if (graceTimer) {
 57→    clearTimeout(graceTimer);
 58→    graceTimer = null;
 59→  }
 60→  if (escalateTimer) {
 61→    clearTimeout(escalateTimer);
 62→    escalateTimer = null;
 63→  }
 64→}
 65→
 66→// --- Store ---
 67→
 68→export const useConnectionStore = create<ConnectionStore>((set, get) => ({
 69→  state: "connected",
 70→  disconnectedAt: null,
 71→  sendAttemptFailed: false,
 72→
 73→  onConnected: () => {
 74→    clearTimers();
 75→    set({ state: "connected", disconnectedAt: null, sendAttemptFailed: false });
 76→  },
 77→
 78→  onDisconnected: () => {
 79→    const current = get().state;
 80→    // Don't re-enter disconnection flow if already in one
 81→    if (current !== "connected") return;
 82→
 83→    const now = Date.now();
 84→    set({ state: "grace_period", disconnectedAt: now, sendAttemptFailed: false });
 85→
 86→    clearTimers();
 87→
 88→    // After GRACE_MS, escalate to reconnecting
 89→    graceTimer = setTimeout(() => {
 90→      if (get().state === "grace_period") {
 91→        get()._escalateToReconnecting();
 92→      }
 93→    }, GRACE_MS);
 94→  },
 95→
 96→  markSendAttemptFailed: () => {
 97→    const current = get().state;
 98→    if (current === "grace_period" || current === "reconnecting") {
 99→      clearTimers();
100→      set({ state: "disconnected", sendAttemptFailed: true });
101→    }
102→  },
103→
104→  retry: () => {
105→    forceReconnect();
106→  },
107→
108→  _escalateToReconnecting: () => {
109→    set({ state: "reconnecting" });
110→
111→    // After ESCALATE_MS from initial disconnect, escalate to fully disconnected
112→    const disconnectedAt = get().disconnectedAt;
113→    if (!disconnectedAt) return;
114→
115→    const elapsed = Date.now() - disconnectedAt;
116→    const remaining = Math.max(0, ESCALATE_MS - elapsed);
117→
118→    escalateTimer = setTimeout(() => {
119→      if (get().state === "reconnecting") {
120→        get()._escalateToDisconnected();
121→      }
122→    }, remaining);
123→  },
124→
125→  _escalateToDisconnected: () => {
126→    set({ state: "disconnected" });
127→  },
128→}));
