394→              </ResizablePanel>
395→            </ResizablePanelGroup>
396→          </div>
397→        ) : (
398→          <div className="flex min-w-0 flex-1">
399→            <WelcomeView
400→              onCreateWorkspace={onCreateWorkspace}
401→              onOpenProject={onOpenProject}
