 82→export function MainLayout() {
 83→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 84→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 85→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 86→
 87→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
 88→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
 89→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
 90→  const settingsOpen = useUIStore((s) => s.settingsOpen);
 91→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
 92→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
 93→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
 94→
 95→  // TanStack Query
 96→  const workspacesQuery = useWorkspacesByRepo();
 97→
 98→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
 99→  const loading = workspacesQuery.isLoading;
100→
101→  // Derive the full workspace object from React Query data.
102→  // The store only holds an ID; this useMemo resolves it to a Workspace
103→  // on every React Query refresh, eliminating the old sync effect entirely.
104→  const selectedWorkspace = useMemo(() => {
105→    if (!selectedWorkspaceId || !repoGroups.length) return null;
106→    for (const group of repoGroups) {
107→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
108→      if (found) return found;
109→    }
110→    return null;
