326→        .catch((error) => {
327→          console.error("Failed to deserialize detached chat insert:", error);
328→        });
329→    });
330→
331→    return () => {
332→      unsubStore();
333→      unlistenChat();
334→    };
335→  }, []);
336→
337→  const handleWorkspaceClick = useCallback(
338→    (workspace: Workspace) => {
339→      selectWorkspace(workspace.id);
340→    },
341→    [selectWorkspace]
342→  );
343→
344→  return (
345→    <SidebarProvider
346→      className="h-full"
347→      data-resizing={sidebarDragging || undefined}
