  1→/**
  2→ * ServerLayout -- web mode shell for a connected server.
  3→ *
  4→ * Wraps routes under /s/$serverId. Handles:
  5→ * - Auth gate: shows PairGatePage for unauthenticated relay clients
  6→ * - Relay WebSocket connection with serverId for endpoint resolution
  7→ * - Connection state UI (connecting, offline, reconnecting)
  8→ *
  9→ * The auth gate renders BEFORE the WS connect hooks fire so we don't
 10→ * attempt a tokenless relay connection that would immediately fail.
 11→ */
 12→
 13→import { useEffect } from "react";
 14→import { Outlet, useParams } from "@tanstack/react-router";
 15→import { Toaster } from "@/components/ui/sonner";
 16→import { initNotifications } from "@/platform/notifications";
 17→import { useGlobalSessionNotifications } from "@/features/session/hooks/useGlobalSessionNotifications";
 18→import { useWorkspaceInitEvents } from "@/features/workspace/hooks/useWorkspaceInitEvents";
 19→import { useQueryProtocol } from "@/shared/hooks/useQueryProtocol";
 20→import { useBackendRestart } from "@/shared/hooks/useBackendRestart";
 21→import { useAnalyticsConsent } from "@/platform/analytics";
 22→import { useSettings } from "@/features/settings";
 23→import { useAuth, PairGatePage } from "@/features/auth";
 24→import { ServerOfflinePage } from "@/features/connection";
 25→import { isRelayMode } from "@/shared/config/backend.config";
 26→
 27→export function ServerLayout() {
 28→  // Extract serverId from route params for relay WS connection
 29→  const { serverId } = useParams({ strict: false }) as { serverId: string };
 30→
 31→  // Auth gate: relay mode requires device token authentication.
 32→  // This must be checked BEFORE mounting ServerContent, because
 33→  // ServerContent's useQueryProtocol will attempt a WS connect that
 34→  // requires a valid device token in relay mode.
 35→  const auth = useAuth();
 36→  const relay = isRelayMode();
 37→
 38→  // Request OS notification permission once on mount
 39→  useEffect(() => {
 40→    initNotifications();
 41→  }, []);
 42→
 43→  // Auth gate for relay mode: show pairing page if not authenticated
 44→  if (relay) {
 45→    if (auth.isLoading) {
 46→      return (
 47→        <div className="bg-background flex h-screen items-center justify-center">
 48→          <div className="text-muted-foreground text-sm">Checking authentication...</div>
 49→        </div>
 50→      );
 51→    }
 52→    if (!auth.isAuthenticated) {
 53→      return <PairGatePage onPaired={auth.onPaired} serverId={serverId} />;
 54→    }
 55→  }
 56→
 57→  // Auth passed (or not needed) — mount the connected content.
 58→  // ServerContent is a separate component so its hooks only run
 59→  // after the auth gate passes (hooks can't be conditional).
 60→  return <ServerContent serverId={serverId} />;
 61→}
 62→
 63→/**
 64→ * Inner component that runs all the WS + data hooks.
 65→ * Only mounted after the auth gate passes, ensuring we have
 66→ * a valid device token before attempting the relay WS connection.
 67→ */
 68→function ServerContent({ serverId }: { serverId: string }) {
 69→  const settingsQuery = useSettings();
 70→
 71→  // Global listeners -- same as DesktopShell
 72→  useGlobalSessionNotifications();
 73→  useWorkspaceInitEvents();
 74→
 75→  // Pass serverId so the WS URL resolves to the correct relay endpoint
 76→  useQueryProtocol(serverId);
 77→
 78→  useBackendRestart();
 79→  useAnalyticsConsent();
 80→
 81→  // While settings load, show a loading state
 82→  if (settingsQuery.isLoading) {
 83→    return (
 84→      <div className="bg-background flex h-screen items-center justify-center">
 85→        <div className="text-muted-foreground text-sm">Connecting...</div>
 86→      </div>
 87→    );
 88→  }
 89→
 90→  // Backend unreachable
 91→  if (settingsQuery.isError && !settingsQuery.data) {
 92→    return (
 93→      <ServerOfflinePage
 94→        onRetry={() => settingsQuery.refetch()}
 95→        variant={isRelayMode() ? "relay" : "desktop"}
 96→      />
 97→    );
 98→  }
 99→
100→  return (
101→    <>
102→      <Outlet />
103→      <Toaster />
104→    </>
105→  );
106→}
107→

  1→/**
  2→ * DesktopShell -- Electron desktop mode, no routing.
  3→ *
  4→ * Contains ALL of the existing AppContent gate logic (auth, settings,
  5→ * onboarding, backend error). Renders MainLayout directly without a router.
  6→ *
  7→ * This is the Electron-only code path. Web mode uses TanStack Router instead.
  8→ */
  9→
 10→import { useEffect, useRef } from "react";
 11→import { ErrorBoundary } from "react-error-boundary";
 12→import { MainLayout } from "../layouts/MainLayout";
 13→import { DashboardError } from "@/shared/components";
 14→import { createBoundaryErrorHandler } from "@/shared/utils/errorReporting";
 15→import { Toaster } from "@/components/ui/sonner";
 16→import { OnboardingOverlay } from "@/features/onboarding";
 17→import { useSettings } from "@/features/settings";
 18→import { useAuth, PairGatePage } from "@/features/auth";
 19→import { native, capabilities } from "@/platform";
 20→import { ServerOfflinePage } from "@/features/connection";
 21→import { initNotifications } from "@/platform/notifications";
 22→import { useGlobalSessionNotifications } from "@/features/session/hooks/useGlobalSessionNotifications";
 23→import { useWorkspaceInitEvents } from "@/features/workspace/hooks/useWorkspaceInitEvents";
 24→import { useQueryProtocol } from "@/shared/hooks/useQueryProtocol";
 25→import { useBackendRestart } from "@/shared/hooks/useBackendRestart";
 26→import { useAutoUpdate, useUpdateToast, UpdateProvider } from "@/features/updates";
 27→import { useAnalyticsConsent } from "@/platform/analytics";
 28→export function DesktopShell({ reset }: { reset: () => void }) {
 29→  const auth = useAuth();
 30→  const settingsQuery = useSettings();
 31→  const windowShownRef = useRef(false);
 32→
 33→  // Request OS notification permission once on mount
 34→  useEffect(() => {
 35→    initNotifications();
 36→  }, []);
 37→
 38→  // Global listener: fire OS notifications for ALL session events when backgrounded
 39→  useGlobalSessionNotifications();
 40→
 41→  // Global listener: workspace init progress -> invalidate queries on completion
 42→  useWorkspaceInitEvents();
 43→
 44→  // Global listener: WS query protocol -> direct cache updates + invalidation dispatch
 45→  useQueryProtocol();
 46→
 47→  // Global listener: backend restart -> update cached port + force WS reconnect
 48→  useBackendRestart();
 49→
 50→  // Sync PostHog opt-in/out state with analytics_enabled setting
 51→  useAnalyticsConsent();
 52→
 53→  // Auto-update: check on launch + every 5 min, show toast when ready
 54→  const autoUpdate = useAutoUpdate();
 55→  useUpdateToast(autoUpdate);
 56→
 57→  const showOnboarding = !settingsQuery.isError && !settingsQuery.data?.onboarding_completed;
 58→
 59→  // Boot diagnostics -- trace the window-show flow so we can see what's blocking
 60→  useEffect(() => {
 61→    if (import.meta.env.DEV) {
 62→      console.log("[DesktopShell] mount -- auth:", {
 63→        isLoading: auth.isLoading,
 64→        isAuthenticated: auth.isAuthenticated,
 65→      });
 66→      console.log("[DesktopShell] mount -- settings:", {
 67→        isLoading: settingsQuery.isLoading,
 68→        isError: settingsQuery.isError,
 69→        hasData: !!settingsQuery.data,
 70→        onboardingCompleted: settingsQuery.data?.onboarding_completed,
 71→        showOnboarding,
 72→      });
 73→    }
 74→  }, [
 75→    auth.isLoading,
 76→    auth.isAuthenticated,
 77→    settingsQuery.isLoading,
 78→    settingsQuery.isError,
 79→    settingsQuery.data,
 80→    showOnboarding,
 81→  ]);
 82→
 83→  // Show the main window whenever we transition OUT of onboarding.
 84→  useEffect(() => {
 85→    if (settingsQuery.isLoading) return;
 86→    if (showOnboarding) {
 87→      windowShownRef.current = false;
 88→      return;
 89→    }
 90→    if (windowShownRef.current) return;
 91→    native.window.show().catch(console.error);
 92→    windowShownRef.current = true;
 93→  }, [settingsQuery.isLoading, showOnboarding]);
 94→
 95→  // Remote browser auth gate: show pairing page if not authenticated
 96→  if (auth.isLoading) return null;
 97→  if (!auth.isAuthenticated) return <PairGatePage onPaired={auth.onPaired} />;
 98→
 99→  // While settings load, render nothing -- window is hidden anyway
100→  if (settingsQuery.isLoading) return null;
101→
102→  // Backend unreachable -- show error instead of white screen
103→  if (settingsQuery.isError && !settingsQuery.data) {
104→    return (
105→      <ServerOfflinePage
106→        onRetry={() => settingsQuery.refetch()}
107→        variant="desktop"
108→      />
109→    );
110→  }
111→
112→  if (showOnboarding) {
113→    return <OnboardingOverlay />;
114→  }
115→
116→  return (
117→    <UpdateProvider value={autoUpdate}>
118→      <ErrorBoundary
119→        FallbackComponent={DashboardError}
120→        onReset={reset}
121→        onError={createBoundaryErrorHandler("react.error-boundary.root")}
122→      >
123→        <MainLayout />
124→      </ErrorBoundary>
125→      <Toaster />
126→    </UpdateProvider>
127→  );
128→}
