  1→/**
  2→ * Session Query Hooks
  3→ * TanStack Query hooks for Claude Code session management
  4→ */
  5→
  6→import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
  7→import { produce } from "immer";
  8→import { SessionService } from "./session.service";
  9→import type { PaginatedMessages } from "./session.service";
 10→import { queryKeys } from "@/shared/api/queryKeys";
 11→import { useQuerySubscription } from "@/shared/hooks/useQuerySubscription";
 12→import {
 13→  MESSAGE_PAGE_SIZE,
 14→  INITIAL_MESSAGE_PAGE_SIZE,
 15→  mergeMessageDelta,
 16→} from "../lib/messageCache";
 17→import type { ContentBlock, Message, Session, SessionStatus } from "../types";
 18→import { isToolResultBlock } from "../types";
 19→import type { RepoGroup } from "@shared/types/workspace";
 20→import { useMemo, useCallback } from "react";
 21→import { track } from "@/platform/analytics";
 22→import { parseContentBlocks } from "../lib/contentParser";
 23→import { sendCommand, connect, isConnected } from "@/platform/ws";
 24→import { emitSendAttemptFailed } from "@/features/connection";
 25→import type { RuntimeAgentType } from "../lib/agentRuntime";
 26→
 27→/**
 28→ * Fetch all sessions for a workspace (used by chat tab reconstruction).
 29→ * Stale time is high — tabs only hydrate on mount and after creating new sessions.
 30→ */
 31→export function useWorkspaceSessions(workspaceId: string | null) {
 32→  useQuerySubscription("sessions", {
 33→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 34→    params: { workspaceId: workspaceId || "" },
 35→    enabled: !!workspaceId,
 36→  });
 37→
 38→  return useQuery({
 39→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 40→    queryFn: () => SessionService.fetchByWorkspace(workspaceId!),
 41→    enabled: !!workspaceId,
 42→    staleTime: Infinity,
 43→    refetchOnWindowFocus: false,
 44→  });
 45→}
 46→
 47→/**
 48→ * Fetch session details — fully WS-driven, no polling.
 49→ *
 50→ * Updates come from WS subscription: backend pushes q:snapshot on
 51→ * session:status, session:updated, and session:message notifications.
 52→ * HTTP queryFn is fallback for initial load before WS connects.
 53→ */
 54→export function useSession(sessionId: string | null) {
 55→  useQuerySubscription("session", {
 56→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 57→    params: { sessionId: sessionId || "" },
 58→    enabled: !!sessionId,
 59→  });
 60→
 61→  return useQuery({
 62→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 63→    queryFn: () => SessionService.fetchById(sessionId!),
 64→    enabled: !!sessionId,
 65→    staleTime: Infinity,
 66→    refetchOnWindowFocus: false,
 67→  });
 68→}
 69→
 70→/**
 71→ * Subscribe to per-session working status for multiple sessions at once.
 72→ * Used by the tab bar to show per-tab spinners correctly.
 73→ *
 74→ * The workspace's single `session_status` field breaks with multiple tabs —
 75→ * it gets overwritten by whichever session's event fires last. This hook
 76→ * subscribes to each session's detail cache reactively so tab spinners
 77→ * reflect each session's actual status.
 78→ *
 79→ * No extra HTTP fetches when data is already in cache (populated by
 80→ * the "session" WS subscription via q:snapshot on status changes).
 81→ */
 82→export function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 83→  const queries = useQueries({
 84→    queries: sessionIds.map((id) => ({
 85→      queryKey: queryKeys.sessions.detail(id),
 86→      queryFn: () => SessionService.fetchById(id),
 87→      staleTime: 30_000,
 88→      select: (data: Session): SessionStatus => data.status,
 89→    })),
 90→  });
 91→
 92→  // Derive working IDs from query results. useMemo deps use `queries`
 93→  // directly — React Compiler requires it. The select: data.status
 94→  // ensures queries only change identity when a status actually changes.
 95→  return useMemo(() => {
 96→    const ids = new Set<string>();
 97→    sessionIds.forEach((id, i) => {
 98→      if (queries[i]?.data === "working") ids.add(id);
 99→    });
100→    return ids;
101→  }, [queries, sessionIds]);
102→}
103→
104→/**
105→ * Fetch messages for a session — fully WS-driven.
106→ *
107→ * WS subscription pushes q:delta frames with new messages since last cursor.
108→ * mergeMessageDelta handles the PaginatedMessages shape, deduplication,
109→ * and optimistic placeholder cleanup.
110→ * HTTP queryFn is fallback for initial load before WS connects.
111→ */
112→export function useMessages(sessionId: string | null) {
113→  useQuerySubscription("messages", {
114→    queryKey: queryKeys.sessions.messages(sessionId || ""),
115→    params: { sessionId: sessionId || "" },
116→    enabled: !!sessionId,
117→    mergeDelta: mergeMessageDelta,
118→  });
119→
120→  const query = useQuery({
121→    queryKey: queryKeys.sessions.messages(sessionId || ""),
122→    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
123→    enabled: !!sessionId,
124→    refetchInterval: false,
125→    staleTime: Infinity,
126→    refetchOnWindowFocus: false,
127→  });
128→
129→  return query;
130→}
131→
132→/**
133→ * Combined hook for session + messages + status
134→ * Replaces the complex useMessages hook
135→ */
136→export function useSessionWithMessages(sessionId: string | null) {
137→  const sessionQuery = useSession(sessionId);
138→  const messagesQuery = useMessages(sessionId);
139→
140→  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
141→  const messages = messagesQuery.data?.messages ?? [];
142→  const hasOlder = messagesQuery.data?.has_older ?? false;
143→
144→  // Parse content helper — delegates to pure function in lib/contentParser.ts
145→  // Memoized to prevent Context cascade re-renders
146→  const parseContent = useCallback(
147→    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
148→    []
149→  );
150→
151→  // Build tool result map and parent_tool_use_id map in a single pass.
152→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
153→    const resultMap = new Map();
154→    const parentMap = new Map<string, string>();
155→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
156→
157→    messages.forEach((msg: Message) => {
158→      if (msg.parent_tool_use_id) {
159→        parentMap.set(msg.id, msg.parent_tool_use_id);
160→      }
161→
162→      const blocks = parseContent(msg.content);
163→      if (Array.isArray(blocks)) {
164→        blocks.filter(isToolResultBlock).forEach((block) => {
165→          resultMap.set(block.tool_use_id, block);
166→        });
167→      }
168→    });
169→
170→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
171→  }, [messages, parseContent]);
172→
173→  // Group subagent messages by their parent Task tool_use_id
174→  const subagentMessages = useMemo(() => {
175→    const map = new Map<string, Message[]>();
176→    if (!messages.length) return map;
177→
178→    messages.forEach((msg: Message) => {
179→      const parentId = parentToolUseMap.get(msg.id);
180→      if (parentId) {
181→        if (!map.has(parentId)) map.set(parentId, []);
182→        map.get(parentId)!.push(msg);
183→      }
184→    });
185→
186→    return map;
187→  }, [messages, parentToolUseMap]);
188→
189→  // Get latest user message's sent_at for duration tracking
190→  const latestMessageSentAt = useMemo(() => {
191→    if (!messages.length) return null;
192→
193→    // Find the latest user message
194→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
195→
196→    return latestUserMessage?.sent_at || null;
197→  }, [messages]);
198→
199→  return {
200→    session: sessionQuery.data,
201→    messages,
202→    hasOlder,
203→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
204→    latestMessageSentAt,
205→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
206→    error: sessionQuery.error || messagesQuery.error,
207→    parseContent,
208→    toolResultMap,
209→    parentToolUseMap,
210→    subagentMessages,
211→  };
212→}
