 34→  /** Called by useConnectionStateInit when WS connects */
 35→  onConnected: () => void;
 36→  /** Called by useConnectionStateInit when WS disconnects */
 37→  onDisconnected: () => void;
 38→  /** Called when a user action (sendMessage) fails due to disconnection */
 39→  markSendAttemptFailed: () => void;
 40→  /** Force immediate reconnect attempt */
 41→  retry: () => void;
 42→  /** Internal: transition from grace to reconnecting */
 43→  _escalateToReconnecting: () => void;
 44→  /** Internal: transition from reconnecting to disconnected */
 45→  _escalateToDisconnected: () => void;
 46→}
 47→
 48→type ConnectionStore = ConnectionStoreState & ConnectionStoreActions;
 49→
 50→// --- Timer refs (module-level, not in store) ---
 51→
 52→let graceTimer: ReturnType<typeof setTimeout> | null = null;
 53→let escalateTimer: ReturnType<typeof setTimeout> | null = null;
 54→
 55→function clearTimers() {
 56→  if (graceTimer) {
 57→    clearTimeout(graceTimer);
 58→    graceTimer = null;
 59→  }
 60→  if (escalateTimer) {
 61→    clearTimeout(escalateTimer);
 62→    escalateTimer = null;
 63→  }
 64→}
 65→
 66→// --- Store ---
 67→
 68→export const useConnectionStore = create<ConnectionStore>((set, get) => ({
 69→  state: "connected",
 70→  disconnectedAt: null,
 71→  sendAttemptFailed: false,
 72→
 73→  onConnected: () => {
 74→    clearTimers();
 75→    set({ state: "connected", disconnectedAt: null, sendAttemptFailed: false });
 76→  },
