 80→    // Don't re-enter if already in the active disconnection flow (grace/reconnecting).
 81→    // Allow re-entry from "disconnected" so that Retry → forceReconnect → onclose
 82→    // can restart the grace period.
 83→    if (current === "grace_period" || current === "reconnecting") return;
