 1→/**
 2→ * Facade hook over the connection Zustand store.
 3→ * Uses selector discipline — each consumer only re-renders
 4→ * when the specific slice it reads changes.
 5→ */
 6→
 7→import { useConnectionStore, type ConnectionState } from "../store/connectionStore";
 8→
 9→export { type ConnectionState };
10→
11→export function useConnectionState() {
12→  const state = useConnectionStore((s) => s.state);
13→  const disconnectedAt = useConnectionStore((s) => s.disconnectedAt);
14→  const sendAttemptFailed = useConnectionStore((s) => s.sendAttemptFailed);
15→  const retry = useConnectionStore((s) => s.retry);
16→  const markSendAttemptFailed = useConnectionStore((s) => s.markSendAttemptFailed);
17→
18→  return { state, disconnectedAt, sendAttemptFailed, retry, markSendAttemptFailed };
19→}
