/**
 * Facade hook over the connection Zustand store.
 * Uses selector discipline — each consumer only re-renders
 * when the specific slice it reads changes.
 */

import { useConnectionStore, type ConnectionState } from "../store/connectionStore";

export { type ConnectionState };

export function useConnectionState() {
  const state = useConnectionStore((s) => s.state);
  const disconnectedAt = useConnectionStore((s) => s.disconnectedAt);
  const sendAttemptFailed = useConnectionStore((s) => s.sendAttemptFailed);
  const retry = useConnectionStore((s) => s.retry);
  const markSendAttemptFailed = useConnectionStore((s) => s.markSendAttemptFailed);

  return { state, disconnectedAt, sendAttemptFailed, retry, markSendAttemptFailed };
}

