interface ConnectionStoreActions {
  /** Called by useConnectionStateInit when WS connects */
  onConnected: () => void;
  /** Called by useConnectionStateInit when WS disconnects */
  onDisconnected: () => void;
  /** Called when a user action (sendMessage) fails due to disconnection */
  markSendAttemptFailed: () => void;
  /** Force immediate reconnect attempt */
  retry: () => void;
  /** Internal: transition from grace to reconnecting */
  _escalateToReconnecting: () => void;
  /** Internal: transition from reconnecting to disconnected */
  _escalateToDisconnected: () => void;
}

type ConnectionStore = ConnectionStoreState & ConnectionStoreActions;

// --- Timer refs (module-level, not in store) ---

let graceTimer: ReturnType<typeof setTimeout> | null = null;
let escalateTimer: ReturnType<typeof setTimeout> | null = null;

function clearTimers() {
  if (graceTimer) {
    clearTimeout(graceTimer);
    graceTimer = null;
  }
  if (escalateTimer) {
    clearTimeout(escalateTimer);
    escalateTimer = null;
  }
}

// --- Store ---

export const useConnectionStore = create<ConnectionStore>((set, get) => ({
  state: "connected",
  disconnectedAt: null,
  sendAttemptFailed: false,

  onConnected: () => {
    clearTimers();
    set({ state: "connected", disconnectedAt: null, sendAttemptFailed: false });
  },

  onDisconnected: () => {
    const current = get().state;
    // Don't re-enter if already in the active disconnection flow (grace/reconnecting).
    // Allow re-entry from "disconnected" so that Retry → forceReconnect → onclose
    // can restart the grace period.
    if (current === "grace_period" || current === "reconnecting") return;

    clearTimers();

    const now = Date.now();
    set({ state: "grace_period", disconnectedAt: now, sendAttemptFailed: false });

    // After GRACE_MS, escalate to reconnecting
    graceTimer = setTimeout(() => {
      if (get().state === "grace_period") {
        get()._escalateToReconnecting();
      }
    }, GRACE_MS);
  },

  markSendAttemptFailed: () => {
    const current = get().state;
    if (current === "grace_period" || current === "reconnecting") {
      clearTimers();
      set({ state: "disconnected", sendAttemptFailed: true });
    }
  },

  retry: () => {
    forceReconnect();
  },

  _escalateToReconnecting: () => {
    set({ state: "reconnecting" });

    // Escalate to DISCONNECTED after ESCALATE_MS total time from initial disconnect
    // (not from entering RECONNECTING). This accounts for time already spent in
    // GRACE_PERIOD, so total disconnect-to-disconnected is always ~30s.
    const disconnectedAt = get().disconnectedAt;
    if (!disconnectedAt) return;

    const elapsed = Date.now() - disconnectedAt;
    const remaining = Math.max(0, ESCALATE_MS - elapsed);

    escalateTimer = setTimeout(() => {
      if (get().state === "reconnecting") {
        get()._escalateToDisconnected();
      }
    }, remaining);
  },

  _escalateToDisconnected: () => {
    set({ state: "disconnected" });
  },
}));

