 1→/**
 2→ * ConnectionOrb — ambient connection health indicator for the sidebar footer.
 3→ *
 4→ * Always renders (unlike the old BackendStatusIndicator which only showed when disconnected).
 5→ * Visual states:
 6→ *   connected    → green dot, static
 7→ *   grace_period → green dot (unchanged — 2s buffer, user sees nothing)
 8→ *   reconnecting → amber dot with breathing pulse
 9→ *   disconnected → amber dot with breathing pulse + "Offline" label
10→ */
11→
12→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
13→import { match } from "ts-pattern";
14→import { cn } from "@/shared/lib/utils";
15→import { useConnectionState, type ConnectionState } from "../hooks/useConnectionState";
16→
17→const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
18→
19→function getAriaLabel(state: ConnectionState): string {
20→  return match(state)
21→    .with("connected", "grace_period", () => "Connected")
22→    .with("reconnecting", () => "Reconnecting")
23→    .with("disconnected", () => "Server disconnected")
24→    .exhaustive();
25→}
26→
27→export function ConnectionOrb() {
28→  const { state } = useConnectionState();
29→  const reduceMotion = useReducedMotion();
30→
31→  const isAmber = state === "reconnecting" || state === "disconnected";
32→  const showLabel = state === "disconnected";
33→  const showPulse = isAmber && !reduceMotion;
34→
35→  return (
36→    <div
37→      className="flex items-center gap-1.5 px-1 py-0.5"
38→      role="status"
39→      aria-label={getAriaLabel(state)}
40→    >
41→      <span className="relative flex h-2 w-2 items-center justify-center">
42→        {/* Breathing pulse ring */}
43→        {showPulse && (
44→          <span className="bg-accent-gold absolute inline-flex h-full w-full animate-ping rounded-full opacity-60" />
45→        )}
46→        {/* Solid dot — CSS transition for color (compositor-friendly) */}
47→        <span
48→          className={cn(
49→            "relative inline-flex h-2 w-2 rounded-full transition-colors duration-300",
50→            isAmber ? "bg-accent-gold" : "bg-accent-green"
51→          )}
52→        />
53→      </span>
54→
55→      {/* "Offline" label — only in disconnected state */}
56→      <AnimatePresence>
57→        {showLabel && (
58→          <m.span
59→            key="connection-label"
60→            className="text-text-muted overflow-hidden whitespace-nowrap text-xs"
61→            initial={reduceMotion ? false : { opacity: 0, x: -4 }}
62→            animate={{ opacity: 1, x: 0 }}
63→            exit={reduceMotion ? { opacity: 0 } : { opacity: 0, x: -4 }}
64→            transition={{ duration: reduceMotion ? 0 : 0.2, ease: EASE_OUT_QUART }}
65→          >
66→            Offline
67→          </m.span>
68→        )}
69→      </AnimatePresence>
70→    </div>
71→  );
72→}
73→

  1→/**
  2→ * ConnectionBanner — top-of-content-area bar for connection issues.
  3→ *
  4→ * Two stages:
  5→ *   RECONNECTING (2-30s): "Reconnecting..." with amber accent
  6→ *   DISCONNECTED (30s+):  "Connection lost" + Retry button
  7→ *
  8→ * Fixed 40px height — only animates transform + opacity (GPU-composited).
  9→ * Content cross-fades between stages via AnimatePresence.
 10→ */
 11→
 12→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
 13→import { useConnectionState } from "../hooks/useConnectionState";
 14→
 15→const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
 16→
 17→export function ConnectionBanner() {
 18→  const { state, sendAttemptFailed, retry } = useConnectionState();
 19→  const reduceMotion = useReducedMotion();
 20→
 21→  const showBanner = state === "reconnecting" || state === "disconnected";
 22→  const isEscalated = state === "disconnected";
 23→
 24→  return (
 25→    <AnimatePresence>
 26→      {showBanner && (
 27→        <m.div
 28→          key="connection-banner"
 29→          role="status"
 30→          aria-live="polite"
 31→          aria-atomic="true"
 32→          className="relative w-full overflow-hidden"
 33→          style={{ height: 40 }}
 34→          initial={
 35→            reduceMotion ? { opacity: 0 } : { opacity: 0, y: -40 }
 36→          }
 37→          animate={{ opacity: 1, y: 0 }}
 38→          exit={
 39→            reduceMotion ? { opacity: 0 } : { opacity: 0, y: -40 }
 40→          }
 41→          transition={{
 42→            duration: reduceMotion ? 0.1 : 0.25,
 43→            ease: EASE_OUT_QUART,
 44→          }}
 45→        >
 46→          {/* Amber bottom accent line */}
 47→          <div className="bg-accent-gold/30 absolute bottom-0 left-0 h-[2px] w-full" />
 48→
 49→          <div className="flex h-full items-center justify-between px-4">
 50→            <div className="flex items-center gap-2.5">
 51→              {/* Amber dot */}
 52→              <span className="relative flex h-1.5 w-1.5">
 53→                <span className="bg-accent-gold absolute inline-flex h-full w-full animate-ping rounded-full opacity-40" />
 54→                <span className="bg-accent-gold relative inline-flex h-1.5 w-1.5 rounded-full" />
 55→              </span>
 56→
 57→              {/* Copy — cross-fades between reconnecting and disconnected */}
 58→              <AnimatePresence mode="wait">
 59→                {isEscalated ? (
 60→                  <m.div
 61→                    key="disconnected-copy"
 62→                    className="flex items-baseline gap-1.5"
 63→                    initial={{ opacity: 0 }}
 64→                    animate={{ opacity: 1 }}
 65→                    exit={{ opacity: 0 }}
 66→                    transition={{ duration: 0.15 }}
 67→                  >
 68→                    <span className="text-text-secondary text-sm font-medium">
 69→                      {sendAttemptFailed ? "Message queued" : "Connection lost"}
 70→                    </span>
 71→                    <span className="text-text-muted text-xs">
 72→                      {sendAttemptFailed
 73→                        ? "— reconnecting"
 74→                        : "— Your agents are still running"}
 75→                    </span>
 76→                  </m.div>
 77→                ) : (
 78→                  <m.span
 79→                    key="reconnecting-copy"
 80→                    className="text-text-muted text-sm"
 81→                    initial={{ opacity: 0 }}
 82→                    animate={{ opacity: 1 }}
 83→                    exit={{ opacity: 0 }}
 84→                    transition={{ duration: 0.15 }}
 85→                  >
 86→                    Reconnecting...
 87→                  </m.span>
 88→                )}
 89→              </AnimatePresence>
 90→            </div>
 91→
 92→            {/* Retry button — only in escalated state */}
 93→            <AnimatePresence>
 94→              {isEscalated && (
 95→                <m.button
 96→                  key="retry-btn"
 97→                  type="button"
 98→                  onClick={retry}
 99→                  className="text-accent-gold hover:text-accent-gold/80 text-xs font-medium transition-colors duration-150"
100→                  initial={{ opacity: 0 }}
101→                  animate={{ opacity: 1 }}
102→                  exit={{ opacity: 0 }}
103→                  transition={{ duration: 0.2 }}
104→                >
105→                  Retry now
106→                </m.button>
107→              )}
108→            </AnimatePresence>
109→          </div>
110→        </m.div>
111→      )}
112→    </AnimatePresence>
113→  );
114→}
