185→  // derived value from the query takes over again (no useEffect + setState).
186→  const [systemPromptEdit, setSystemPromptEdit] = useState<string | null>(null);
187→  const systemPromptDraft = systemPromptEdit ?? (systemPromptQuery.data || "");
188→  const setSystemPromptDraft = useCallback((value: string) => setSystemPromptEdit(value), []);
189→
190→  async function saveSystemPrompt() {
191→    if (!selectedWorkspace) return;
192→    try {
193→      await updateSystemPromptMutation.mutateAsync({
194→        workspaceId: selectedWorkspace.id,
195→        systemPrompt: systemPromptDraft,
196→      });
197→      closeSystemPromptModal();
198→      setSystemPromptEdit(null);
199→    } catch (error) {
200→      console.error("Failed to save system prompt:", error);
201→      toast.error(getErrorMessage(error));
202→    }
203→  }
204→
205→  // --- Archive with undo (ref-stable for memoized sidebar items) ---
206→
207→  const archiveWorkspaceMutation = useArchiveWorkspace();
208→  const unarchiveMutation = useUnarchiveWorkspace();
209→
210→  // Ref-stable archive handler: archiveWorkspaceMutation and selectedWorkspace
211→  // change frequently (every render / every workspace click), so we capture
212→  // them in refs to keep the callback identity stable. This matters because
213→  // onArchive flows through the entire sidebar tree to every memoized WorkspaceItem.
214→  const archiveMutationRef = useRef(archiveWorkspaceMutation);
215→  const unarchiveMutationRef = useRef(unarchiveMutation);
216→  const selectedWorkspaceRef = useRef(selectedWorkspace);
217→  useEffect(() => {
218→    archiveMutationRef.current = archiveWorkspaceMutation;
219→    unarchiveMutationRef.current = unarchiveMutation;
220→    selectedWorkspaceRef.current = selectedWorkspace;
221→  });
222→
223→  const archiveWorkspace = useCallback(
224→    async (workspaceId: string) => {
225→      try {
226→        await archiveMutationRef.current.mutateAsync(workspaceId);
227→        if (selectedWorkspaceRef.current?.id === workspaceId) {
228→          selectWorkspace(null);
229→        }
230→        toast("Workspace archived", {
231→          duration: 5000,
232→          action: {
233→            label: "Undo",
234→            onClick: () => {
235→              unarchiveMutationRef.current.mutateAsync(workspaceId).catch((error) => {
236→                toast.error(getErrorMessage(error));
237→              });
238→            },
239→          },
240→        });
241→      } catch (error) {
242→        console.error("Error archiving workspace:", error);
243→        toast.error(getErrorMessage(error));
244→      }
245→    },
246→    [selectWorkspace]
247→  );
248→
249→  // --- Workflow status change (ref-stable like archive) ---
250→
251→  const statusMutation = useUpdateWorkspaceStatus();
252→  const statusMutationRef = useRef(statusMutation);
253→  useEffect(() => {
254→    statusMutationRef.current = statusMutation;
255→  });
256→
257→  const handleStatusChange = useCallback(
258→    (workspaceId: string, status: import("@shared/enums").WorkspaceStatus) => {
259→      statusMutationRef.current.mutate(
260→        { workspaceId, status },
261→        { onError: (error) => toast.error(getErrorMessage(error)) }
262→      );
263→    },
264→    []
265→  );
266→
267→  // --- Global hooks ---
268→
269→  // Connection state machine — subscribes to WS changes + send-attempt-failed events
270→  useConnectionStateInit();
271→
272→  // Zoom (Cmd+=/Cmd+-/Cmd+0)
273→  useZoom();
274→
275→  // Track fullscreen state — toggles `.fullscreen` class on <html> for CSS
276→  useIsFullscreen();
277→
278→  // Adds .electron class to <html> and injects CSS-only drag region rules.
279→  // Headers with .drag-region class become draggable; buttons auto-excluded.
280→  useWindowDragZone();
281→
282→  // Disable CSS transitions during native window resize to prevent content "sticking"
283→  useWindowResizing();
284→
285→  // Keyboard shortcuts
286→  useKeyboardShortcuts({
287→    onRefresh: async () => {
288→      workspacesQuery.refetch();
289→      if (selectedWorkspace) {
290→        prStatusQuery.refetch();
291→      }
292→    },
293→    onEscape: () => {
294→      if (showNewWorkspaceModal) {
295→        closeNewWorkspaceModal();
296→      } else if (showSystemPromptModal) {
297→        closeSystemPromptModal();
298→      }
299→    },
300→    selectedWorkspace,
301→    modalStates: {
302→      showNewWorkspaceModal,
303→      showSystemPromptModal,
304→    },
305→  });
306→
307→  // Subscribe to chatInsertStore for content dispatched from BrowserPanel / DiffViewer / SimulatorPanel
308→  useEffect(() => {
309→    const unsubStore = useChatInsertStore.subscribe((state, prevState) => {
310→      if (!state.pending || state.pending === prevState.pending) return;
311→
312→      const payload = state.pending;
313→      chatInsertActions.consume();
314→
315→      if (!workspaceChatPanelRef.current) return;
316→      if (!isChatInsertForWorkspace(payload, selectedWorkspaceIdRef.current)) return;
317→
318→      deliverChatInsertPayload(workspaceChatPanelRef.current, payload);
319→    });
320→
321→    const unlistenChat = native.events.on(CHAT_INSERT, (data) => {
322→      void deserializeChatInsertPayload(data)
323→        .then((payload) => {
324→          chatInsertActions.dispatch(payload);
325→        })
326→        .catch((error) => {
327→          console.error("Failed to deserialize detached chat insert:", error);
328→        });
329→    });
330→
331→    return () => {
332→      unsubStore();
333→      unlistenChat();
334→    };
335→  }, []);
336→
337→  const handleWorkspaceClick = useCallback(
338→    (workspace: Workspace) => {
339→      selectWorkspace(workspace.id);
340→    },
341→    [selectWorkspace]
342→  );
343→
344→  return (
345→    <SidebarProvider
346→      className="h-full"
347→      data-resizing={sidebarDragging || undefined}
348→      style={
349→        {
350→          "--sidebar-width": sidebarWidth ? `${sidebarWidth}px` : "344px",
351→          "--sidebar-width-mobile": "344px",
352→        } as React.CSSProperties
353→      }
354→    >
355→      {/* Sidebar — swap between app sidebar and settings sidebar */}
356→      {settingsOpen ? (
357→        <SettingsSidebar />
358→      ) : loading ? (
359→        <SidebarSkeleton />
360→      ) : (
361→        <AppSidebar
362→          repositories={repoGroups}
363→          selectedWorkspaceId={selectedWorkspace?.id || null}
364→          diffStatsMap={bulkDiffStatsQuery.data}
365→          onWorkspaceClick={handleWorkspaceClick}
366→          onNewWorkspace={repoActions.handleNewWorkspace}
367→          onNewWorkspaceFromGitHub={setGithubPickerRepoId}
368→          onAddRepository={repoActions.handleOpenProject}
369→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
370→          onArchive={archiveWorkspace}
371→          onStatusChange={handleStatusChange}
372→          profile={{ username }}
373→        />
374→      )}
375→
376→      {/* Sidebar resize handle */}
377→      <SidebarResizeHandle onSizeChange={setSidebarWidth} onDraggingChange={setSidebarDragging} />
378→
379→      {/* Main Content — swap between app content and settings page */}
380→      {settingsOpen ? (
381→        <SettingsPage />
382→      ) : (
383→        <MainContent
384→          selectedWorkspace={selectedWorkspace}
385→          prStatus={prStatusQuery.data ?? null}
386→          ghStatus={ghStatusQuery.data}
387→          workspaceChatPanelRef={workspaceChatPanelRef}
388→          onCreateWorkspace={openNewWorkspaceModal}
389→          onOpenProject={repoActions.handleOpenProject}
390→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
391→        />
392→      )}
393→
394→      {/* Modals */}
395→      <NewWorkspaceModal
396→        show={showNewWorkspaceModal}
397→        repos={repos}
398→        selectedRepoId={repoActions.selectedRepoId}
399→        creating={repoActions.creating}
400→        onClose={closeNewWorkspaceModal}
401→        onRepoChange={repoActions.setSelectedRepoId}
402→        onCreate={
403→          newWorkspaceMode === "from-github"
404→            ? () => {
405→                const repoId = repoActions.selectedRepoId;
406→                closeNewWorkspaceModal();
407→                if (repoId) setGithubPickerRepoId(repoId);
408→              }
409→            : repoActions.createWorkspaceFromModal
410→        }
411→        mode={newWorkspaceMode}
412→      />
413→
414→      <SystemPromptModal
415→        show={showSystemPromptModal && !!selectedWorkspace}
416→        workspaceName={selectedWorkspace?.slug || ""}
417→        systemPrompt={systemPromptDraft}
418→        loading={systemPromptQuery.isLoading}
419→        saving={updateSystemPromptMutation.isPending}
420→        onClose={() => {
421→          closeSystemPromptModal();
422→          setSystemPromptEdit(null);
423→        }}
424→        onChange={setSystemPromptDraft}
425→        onSave={saveSystemPrompt}
426→      />
427→
428→      <CloneRepositoryModal
429→        show={repoActions.showCloneModal}
430→        cloning={repoActions.cloning}
431→        error={repoActions.cloneError}
432→        statusMessage={repoActions.cloneStatus}
433→        onClose={repoActions.closeCloneModal}
434→        onClone={repoActions.handleCloneRepository}
435→        onClearError={repoActions.clearCloneError}
436→      />
437→
438→      <GitHubPickerModal
439→        open={!!githubPickerRepoId}
440→        onOpenChange={(open) => !open && setGithubPickerRepoId(null)}
441→        repoId={githubPickerRepoId || ""}
442→        repoName={githubPickerRepoName}
443→        onCreateWorkspace={repoActions.handleNewWorkspaceFromGitHub}
444→      />
445→
446→      {/* Command Palette (Cmd+K) */}
447→      <CommandPalette
448→        actionOverrides={{
449→          "open-project": repoActions.handleOpenProject,
450→          "clone-repository": () => repoActions.setShowCloneModal(true),
451→        }}
452→      />
453→    </SidebarProvider>
454→  );
455→}
