  1→/**
  2→ * Main Content -- layout orchestrator.
  3→ *
  4→ * Two-panel horizontal split (40/60 default ratio):
  5→ *   SESSION PANEL (left, 40%):  WorkspaceHeader → SessionTabs → Chat → Input
  6→ *   CONTENT PANEL (right, 60%): ContentTabBar + PRActions → ContentArea
  7→ *
  8→ * Each panel has its own header bar. The split is the top-level layout.
  9→ * Content tab switching (Code, Config, Terminal, etc.) lives in the
 10→ * content panel's header. PR actions also live in the content panel header.
 11→ *
 12→ * Panel resizing uses react-resizable-panels for keyboard accessibility,
 13→ * touch support, and built-in collapse/expand with snap behavior.
 14→ *
 15→ * Concerns are split across extracted hooks:
 16→ * - useWorkspaceActions: PR bridge, archive, retry, manifest tasks
 17→ * - useKeyboardShortcuts: Cmd+\ toggles session panel
 18→ */
 19→
 20→import { useRef, useCallback, useMemo, useEffect } from "react";
 21→import type { ImperativePanelHandle } from "react-resizable-panels";
 22→import type { SessionPanelRef } from "@/features/session";
 23→import { WelcomeView } from "@/features/repository";
 24→import { useWorkspaceLayout } from "@/features/workspace";
 25→import { useCollapsedSizePercent } from "@/features/workspace/hooks/useCollapsedSizePercent";
 26→import type { RightSideTab } from "@/features/workspace/store";
 27→import { useFileWatcher } from "@/features/file-browser/hooks/useFileWatcher";
 28→import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
 29→import { ContentTabBar, isTabVisible } from "@/features/workspace/ui/ContentTabBar";
 30→import { PRActions } from "@/features/workspace/ui/PRActions";
 31→import { useSettings } from "@/features/settings/api/settings.queries";
 32→import { SidebarInset, useSidebar } from "@/components/ui";
 33→import { cn } from "@/shared/lib/utils";
 34→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 35→import { PanelLeft } from "lucide-react";
 36→import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
 37→import { useUpdateWorkspaceStatus } from "@/features/workspace/api";
 38→import { REVIEW_CODE } from "@/features/session/lib/sessionPrompts";
 39→import { native } from "@/platform";
 40→import { BROWSER_WORKSPACE_CHANGE } from "@shared/events";
 41→import { useBrowserWindowStore } from "@/features/browser/store";
 42→import { track } from "@/platform/analytics";
 43→import { ConnectionBanner, useConnectionState } from "@/features/connection";
 44→import { ChatArea } from "./ChatArea";
 45→import { RightSidePanel } from "./RightSidePanel";
 46→import { CollapsedChatStrip, CollapsedContentStrip } from "./CollapsedPanelStrips";
 47→import { useWorkspaceActions } from "./hooks/useWorkspaceActions";
 48→import { usePanelShortcuts } from "./hooks/usePanelShortcuts";
 49→
 50→interface MainContentProps {
 51→  selectedWorkspace: Workspace | null;
 52→  prStatus: PRStatus | null;
 53→  ghStatus?: GhCliStatus | null;
 54→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 55→  onCreateWorkspace: () => void;
 56→  onOpenProject: () => void;
 57→  onCloneRepository: () => void;
 58→}
 59→
 60→export function MainContent({
 61→  selectedWorkspace,
 62→  prStatus,
 63→  ghStatus,
 64→  workspaceChatPanelRef,
 65→  onCreateWorkspace,
 66→  onOpenProject,
 67→  onCloneRepository,
 68→}: MainContentProps) {
 69→  const { open: sidebarOpen, toggleSidebar } = useSidebar();
 70→
 71→  const selectedWorkspaceId = selectedWorkspace?.id ?? null;
 72→  const {
 73→    rightSideTab,
 74→    setRightSideTab,
 75→    chatPanelCollapsed,
 76→    setChatPanelCollapsed,
 77→    rightPanelCollapsed,
 78→    setRightPanelCollapsed,
 79→  } = useWorkspaceLayout(selectedWorkspaceId);
 80→
 81→  // Effective tab: if the stored tab is hidden by experimental settings, fall back to "code".
 82→  const experimentalSettings = useSettings().data;
 83→  const effectiveRightSideTab = isTabVisible(rightSideTab, experimentalSettings)
 84→    ? rightSideTab
 85→    : "code";
 86→
 87→  const isBrowserDetached = useBrowserWindowStore((s) => s.detachedWindowOpen);
 88→  const connectionState = useConnectionState().state;
 89→  const isDisconnected = connectionState === "disconnected";
 90→
 91→  // --- Workspace actions (PR bridge, archive, retry, manifest) ---
 92→  const {
 93→    createPRHandler,
 94→    setCreatePRHandler,
 95→    sendAgentMessageHandler,
 96→    setSendAgentMessageHandler,
 97→    selectedTargetBranch,
 98→    setSelectedTargetBranch,
 99→    handleCreatePR,
100→    handleSendAgentMessage,
101→    handleArchive,
102→    handleRetrySetup,
103→    handleViewSetupLogs,
104→    manifestTasks,
105→    hasManifest,
106→    handleRunTask,
107→  } = useWorkspaceActions({
108→    selectedWorkspace,
109→    setRightSideTab,
110→  });
111→
112→  const statusMutation = useUpdateWorkspaceStatus();
113→
114→  // Only start watching and querying diffs once the worktree checkout is complete.
115→  const isReady = selectedWorkspace?.state === "ready";
116→
117→  // Watch workspace for file changes (event-driven cache invalidation)
118→  const isWatched = useFileWatcher(
119→    isReady ? (selectedWorkspace?.workspace_path ?? null) : null,
120→    isReady ? selectedWorkspaceId : null
121→  );
122→
123→  // --- Refs for imperative panel control ---
124→  const chatPanelRef = useRef<ImperativePanelHandle>(null);
125→  const contentPanelRef = useRef<ImperativePanelHandle>(null);
126→  const panelGroupContainerRef = useRef<HTMLDivElement>(null);
127→
128→  // Dynamic collapsed size: 36px strip -> percentage of container width.
129→  const MIN_PANEL_SIZE = 15;
130→  const collapsedSizePct = useCollapsedSizePercent(panelGroupContainerRef, 36);
131→  const safeCollapsedSize = Math.min(collapsedSizePct, MIN_PANEL_SIZE - 0.1);
132→
133→  // Default split: 40% session / 60% content — same for all tabs.
134→  const sessionPanelDefaultSize = 40;
135→  const contentPanelDefaultSize = 60;
136→
137→  const sessionStatus = selectedWorkspace?.session_status;
138→  const isSessionWorking = sessionStatus === "working";
139→
140→  // --- Content tab change ---
141→  const handleContentTabChange = useCallback(
142→    (tab: RightSideTab) => {
143→      setRightSideTab(tab);
144→      // Track feature surface adoption — fire on every user-initiated tab switch.
145→      // We use a static map instead of ts-pattern here because these are all
146→      // simple string→event mappings with no branching logic.
147→      const tabEventMap: Partial<Record<RightSideTab, () => void>> = {
148→        terminal: () =>
149→          track("terminal_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
150→        browser: () => track("browser_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
151→        simulator: () =>
152→          track("simulator_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
153→        code: () => track("diff_viewed", { workspace_id: selectedWorkspaceId ?? undefined }),
154→      };
155→      tabEventMap[tab]?.();
156→    },
157→    [setRightSideTab, selectedWorkspaceId]
158→  );
159→
160→  // --- Chat panel collapse/expand ---
161→  const handleCollapseChatPanel = useCallback(() => {
162→    setChatPanelCollapsed(true);
163→    chatPanelRef.current?.collapse();
164→  }, [setChatPanelCollapsed]);
165→
166→  const handleExpandChatPanel = useCallback(() => {
167→    setChatPanelCollapsed(false);
168→  }, [setChatPanelCollapsed]);
169→
170→  // --- Content panel collapse/expand ---
171→  const handleCollapseContentPanel = useCallback(() => {
172→    setRightPanelCollapsed(true);
173→    contentPanelRef.current?.collapse();
174→  }, [setRightPanelCollapsed]);
175→
176→  const handleExpandContentPanel = useCallback(() => {
177→    setRightPanelCollapsed(false);
178→  }, [setRightPanelCollapsed]);
179→
180→  // --- Keyboard shortcuts ---
181→  usePanelShortcuts({
182→    enabled: selectedWorkspace !== null,
183→    chatPanelCollapsed,
184→    chatPanelRef,
185→    contentPanelCollapsed: rightPanelCollapsed,
186→    contentPanelRef,
187→  });
188→
189→  // --- Reset panel sizes on workspace switch ---
190→  // ResizablePanelGroup has no key prop — it stays mounted across workspace
191→  // switches so SimulatorPanel and BrowserPanel keep their native sessions alive.
192→  // Without the key, react-resizable-panels won't re-apply defaultSize on
193→  // re-render. We must imperatively collapse/expand panels to match the
194→  // per-workspace Zustand state when the selected workspace changes.
195→  useEffect(() => {
196→    if (!selectedWorkspaceId) return;
197→    if (chatPanelCollapsed) {
198→      chatPanelRef.current?.collapse();
199→    } else {
200→      chatPanelRef.current?.expand();
201→      chatPanelRef.current?.resize(sessionPanelDefaultSize);
202→    }
203→    if (rightPanelCollapsed) {
204→      contentPanelRef.current?.collapse();
205→    } else {
206→      contentPanelRef.current?.expand();
207→      contentPanelRef.current?.resize(contentPanelDefaultSize);
208→    }
209→    // eslint-disable-next-line react-hooks/exhaustive-deps -- only fire on workspace change, not on collapse toggles
210→  }, [selectedWorkspaceId]);
211→
212→  // --- Hide all native BrowserViews on workspace switch ---
213→  // BrowserViews are native Electron overlays rendered ABOVE the DOM. When
214→  // switching workspaces or going to the welcome screen, stale views from
215→  // the previous workspace would remain visible. Hide them immediately;
216→  // the new workspace's BrowserTab will re-show its own view when ready.
217→  useEffect(() => {
218→    native.browserViews.hideAll().catch(() => {});
219→  }, [selectedWorkspaceId]);
220→
221→  // --- Sync workspace changes to detached browser window ---
222→  const detachedWorkspaceContext = useMemo(
223→    () =>
224→      selectedWorkspace
225→        ? {
226→            workspaceId: selectedWorkspace.id,
227→            directoryName: selectedWorkspace.slug,
228→            repoName: selectedWorkspace.repo_name,
229→            branch: selectedWorkspace.git_branch,
230→          }
231→        : null,
232→    [selectedWorkspace]
233→  );
234→
235→  useEffect(() => {
236→    if (!isBrowserDetached || !detachedWorkspaceContext) return;
237→    void native.events.send(BROWSER_WORKSPACE_CHANGE, detachedWorkspaceContext);
238→  }, [isBrowserDetached, detachedWorkspaceContext]);
239→
240→  // Switching to code tab — used by file clicks (diff or preview) in RightSidePanel.
241→  const handleSwitchToCodeTab = useCallback(() => {
242→    setRightSideTab("code");
243→  }, [setRightSideTab]);
244→
245→  // Insert code review prompt into chat input
246→  const handleInsertReviewPrompt = useCallback(() => {
247→    workspaceChatPanelRef.current?.insertText(REVIEW_CODE);
248→  }, [workspaceChatPanelRef]);
249→
250→  return (
251→    <SidebarInset className="min-w-0">
252→      {/* Connection banner — appears at top of content area when WS is down */}
253→      <ConnectionBanner />
254→
255→      <div
256→        data-slot="main-content"
257→        className={cn(
258→          "bg-bg-surface flex h-full min-w-0 flex-1 overflow-hidden border transition-[border-radius,border-color,opacity] duration-[280ms] ease-[cubic-bezier(.19,1,.22,1)]",
259→          sidebarOpen
260→            ? "border-border-subtle rounded-l-xl border-r-0"
261→            : "rounded-none border-transparent",
262→          isDisconnected && "opacity-60"
263→        )}
264→      >
265→        {/* Sidebar toggle -- visible when sidebar collapsed and no workspace */}
266→        {!sidebarOpen && !selectedWorkspace && (
267→          <button
268→            type="button"
269→            data-slot="welcome-sidebar-toggle"
270→            aria-label="Expand sidebar"
271→            onClick={toggleSidebar}
272→            className="text-muted-foreground/60 hover:text-foreground hover:bg-foreground/5 absolute top-3 left-3 z-10 flex h-7 w-7 items-center justify-center rounded-lg transition-[transform,color,background-color] duration-200 ease-out"
273→          >
274→            <PanelLeft className="h-4 w-4" />
275→          </button>
276→        )}
277→
278→        {selectedWorkspace ? (
279→          /* Two-panel split — the top-level layout, no full-width header */
280→          <div ref={panelGroupContainerRef} className="min-h-0 min-w-0 flex-1">
281→            <ResizablePanelGroup direction="horizontal">
282→              {/* ─── SESSION PANEL (left, collapsible) ─── */}
283→              <ResizablePanel
284→                ref={chatPanelRef}
285→                collapsible
286→                collapsedSize={safeCollapsedSize}
287→                minSize={MIN_PANEL_SIZE}
288→                defaultSize={chatPanelCollapsed ? safeCollapsedSize : sessionPanelDefaultSize}
289→                onCollapse={handleCollapseChatPanel}
290→                onExpand={handleExpandChatPanel}
291→                className="min-w-0"
292→                order={1}
293→              >
294→                {chatPanelCollapsed ? (
295→                  <CollapsedChatStrip
296→                    onExpand={() => chatPanelRef.current?.expand()}
297→                    isWorking={isSessionWorking}
298→                  />
299→                ) : (
300→                  <div className="flex h-full min-w-0 flex-col">
301→                    {/* Title header — workspace name + repo/branch + Open */}
302→                    <WorkspaceHeader
303→                      title={selectedWorkspace.title ?? undefined}
304→                      repositoryName={selectedWorkspace.repo_name}
305→                      branch={selectedWorkspace.git_branch ?? undefined}
306→                      workspacePath={selectedWorkspace.workspace_path}
307→                      setupStatus={selectedWorkspace.setup_status}
308→                      setupError={selectedWorkspace.error_message}
309→                      onSendAgentMessage={
310→                        sendAgentMessageHandler ? handleSendAgentMessage : undefined
311→                      }
312→                      onRetrySetup={
313→                        selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
314→                      }
315→                      onViewSetupLogs={
316→                        selectedWorkspace.setup_status === "failed"
317→                          ? handleViewSetupLogs
318→                          : undefined
319→                      }
320→                      workspaceStatus={selectedWorkspace.status}
321→                      onStatusChange={(status) =>
322→                        statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
323→                      }
324→                      tasks={manifestTasks}
325→                      hasManifest={hasManifest}
326→                      onRunTask={handleRunTask}
327→                    />
328→
329→                    {/* Session tabs + chat messages + input */}
330→                    <ChatArea
331→                      key={selectedWorkspace.id}
332→                      workspace={selectedWorkspace}
333→                      workspaceChatPanelRef={workspaceChatPanelRef}
334→                      onCreatePRHandlerChange={setCreatePRHandler}
335→                      onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
336→                      onCollapseChatPanel={handleCollapseChatPanel}
337→                    />
338→                  </div>
339→                )}
340→              </ResizablePanel>
341→
342→              <ResizableHandle />
343→
344→              {/* ─── CONTENT PANEL (right, collapsible) ─── */}
345→              <ResizablePanel
346→                ref={contentPanelRef}
347→                collapsible
348→                collapsedSize={safeCollapsedSize}
349→                defaultSize={rightPanelCollapsed ? safeCollapsedSize : contentPanelDefaultSize}
