  1→/**
  2→ * WebSocket Query Protocol Client
  3→ *
  4→ * Singleton client that connects to the backend's /ws endpoint and handles
  5→ * the q:* protocol for real-time data subscriptions, one-shot requests,
  6→ * mutations, and async commands.
  7→ *
  8→ * Protocol:
  9→ *   Client sends: q:subscribe, q:unsubscribe, q:request, q:mutate, q:command
 10→ *   Server sends: q:snapshot, q:delta, q:response, q:mutate_result, q:command_ack, q:error, q:event, ping
 11→ *   Client responds to ping with pong
 12→ *
 13→ * Relay mode (web-production):
 14→ *   Connects through cloud relay at wss://relay.rundeus.com/api/servers/{id}/connect
 15→ *   Sends { type: "authenticate", token } on open for device token auth.
 16→ *   Handles relay control frames: authenticated, auth_failed, server_reconnecting, server_connected.
 17→ *
 18→ * On reconnect, all active subscriptions are re-established automatically.
 19→ */
 20→
 21→import { match } from "ts-pattern";
 22→import { resolveBackendEndpoints, isRelayMode } from "@/shared/config/backend.config";
 23→import { getStoredToken, signOut } from "@/features/auth";
 24→import type { QueryResource, CommandName } from "@shared/types/query-protocol";
 25→
 26→// ---- Types ----
 27→
 28→type SnapshotCallback = (data: unknown) => void;
 29→type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
 30→type EventCallback = (event: string, data: unknown) => void;
 31→
 32→interface PendingCommand {
 33→  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
 34→  reject: (err: Error) => void;
 35→}
 36→
 37→interface PendingRequest {
 38→  resolve: (data: unknown) => void;
 39→  reject: (err: Error) => void;
 40→  timer: ReturnType<typeof setTimeout>;
 41→}
 42→
 43→interface PendingMutation {
 44→  resolve: (result: { success: boolean; data?: unknown; error?: string }) => void;
 45→  reject: (err: Error) => void;
 46→  timer: ReturnType<typeof setTimeout>;
 47→}
 48→
 49→interface Subscription {
 50→  id: string;
 51→  resource: QueryResource;
 52→  params?: Record<string, unknown>;
 53→  onSnapshot: SnapshotCallback;
 54→  onDelta?: DeltaCallback;
 55→}
 56→
 57→// ---- Reconnect Config ----
 58→
 59→const BACKOFF_BASE_MS = 500;
 60→const BACKOFF_MAX_MS = 8000;
 61→
 62→// ---- Singleton State ----
 63→
 64→let ws: WebSocket | null = null;
 65→let _connectionId: string | null = null;
 66→let connected = false;
 67→let connecting = false;
 68→let reconnectAttempt = 0;
 69→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 70→let subCounter = 0;
 71→
 72→/** Active subscriptions keyed by client-assigned ID. */
 73→const subscriptions = new Map<string, Subscription>();
 74→
 75→/** Pending commands waiting for q:command_ack. */
 76→const pendingCommands = new Map<string, PendingCommand>();
 77→
 78→/** Pending one-shot q:request frames waiting for q:response. */
 79→const pendingRequests = new Map<string, PendingRequest>();
 80→
 81→/** Pending q:mutate frames waiting for q:mutate_result. */
 82→const pendingMutations = new Map<string, PendingMutation>();
 83→
 84→/** Listeners for q:event broadcasts. */
 85→const eventListeners = new Set<EventCallback>();
 86→
 87→/** Listeners notified when connection state changes (connected/disconnected). */
 88→const connectionChangeListeners = new Set<(connected: boolean) => void>();
 89→
 90→/** Counter for generating unique command frame IDs. */
 91→let commandCounter = 0;
 92→
 93→/** Counter for generating unique request/mutation frame IDs. */
 94→let requestCounter = 0;
 95→
 96→/** Resolvers waiting for the initial "connected" frame after open. */
 97→let connectResolve: (() => void) | null = null;
 98→let connectReject: ((err: Error) => void) | null = null;
 99→
100→// ---- Public API ----
101→
102→/** Generate a unique subscription ID. */
103→function nextSubId(): string {
104→  return `sub_${++subCounter}`;
105→}
106→
107→/**
108→ * Connect to the backend WebSocket. Resolves once authenticated.
109→ * No-op if already connected or connecting.
110→ *
111→ * In relay mode, pass the serverId so the WS URL can be resolved.
112→ */
113→export async function connect(serverId?: string): Promise<void> {
114→  if (connected) return;
115→  if (connecting) {
116→    // Wait for the in-flight connection attempt
117→    return new Promise<void>((resolve, reject) => {
118→      const prevResolve = connectResolve;
119→      const prevReject = connectReject;
120→      connectResolve = () => {
121→        prevResolve?.();
122→        resolve();
123→      };
124→      connectReject = (err) => {
125→        prevReject?.(err);
126→        reject(err);
127→      };
128→    });
129→  }
130→
131→  connecting = true;
132→
133→  return new Promise<void>((resolve, reject) => {
134→    connectResolve = resolve;
135→    connectReject = reject;
136→    openSocket(serverId).catch((err) => {
137→      connecting = false;
138→      connectReject?.(err);
139→      connectResolve = null;
140→      connectReject = null;
141→    });
142→  });
143→}
144→
145→/**
146→ * Subscribe to a query resource. Returns an unsubscribe function.
147→ *
148→ * On subscription, the server sends an initial q:snapshot. Subsequent
149→ * invalidations push q:snapshot (full replace) or q:delta (incremental).
150→ */
151→export function subscribe(
152→  resource: QueryResource,
153→  params: Record<string, unknown> | undefined,
154→  onSnapshot: SnapshotCallback,
155→  onDelta?: DeltaCallback
156→): () => void {
157→  const id = nextSubId();
158→  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
159→  subscriptions.set(id, sub);
160→
161→  // If connected, send subscribe frame immediately
162→  if (connected && ws) {
163→    sendFrame({
164→      type: "q:subscribe",
165→      id,
166→      resource,
167→      ...(params ? { params } : {}),
168→    });
169→  }
170→
171→  // Return unsubscribe function
172→  return () => {
173→    subscriptions.delete(id);
174→    if (connected && ws) {
175→      sendFrame({ type: "q:unsubscribe", id });
176→    }
177→  };
178→}
179→
180→/** Check if the client is currently connected. */
181→export function isConnected(): boolean {
182→  return connected;
183→}
184→
185→/**
186→ * Send an async command via the q:command frame.
187→ * Returns a promise that resolves when the server sends q:command_ack.
188→ */
189→export function sendCommand(
190→  command: CommandName,
191→  params: Record<string, unknown>
192→): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
193→  const id = `cmd_${++commandCounter}`;
194→
195→  return new Promise((resolve, reject) => {
196→    pendingCommands.set(id, { resolve, reject });
197→
198→    const sent = sendFrame({
199→      type: "q:command",
200→      id,
201→      command,
202→      params,
203→    });
204→
205→    // Reject immediately if the frame couldn't be sent (WS disconnected)
206→    if (!sent) {
207→      pendingCommands.delete(id);
208→      reject(new Error("WebSocket not connected"));
209→      return;
210→    }
211→
212→    // Timeout after 30s to prevent leaked promises
213→    setTimeout(() => {
214→      if (pendingCommands.has(id)) {
215→        pendingCommands.delete(id);
216→        reject(new Error(`Command ${command} timed out`));
217→      }
218→    }, 30_000);
219→  });
220→}
221→
222→/**
223→ * Send a one-shot data request via the q:request frame.
224→ * Returns a promise that resolves with the response data when the
225→ * server sends q:response, or rejects on q:error or timeout.
226→ *
227→ * Works with both subscribable (QueryResource) and request-only
228→ * (RequestResource) resources.
229→ */
230→export function sendRequest<T = unknown>(
231→  resource: string,
232→  params?: Record<string, unknown>
233→): Promise<T> {
234→  const id = `req_${++requestCounter}`;
235→  const REQUEST_TIMEOUT_MS = 30_000;
236→
237→  return new Promise<T>((resolve, reject) => {
238→    const timer = setTimeout(() => {
239→      pendingRequests.delete(id);
240→      reject(new Error(`Request ${resource} timed out`));
241→    }, REQUEST_TIMEOUT_MS);
242→
243→    pendingRequests.set(id, {
244→      resolve: resolve as (data: unknown) => void,
245→      reject,
246→      timer,
247→    });
248→
249→    const sent = sendFrame({
250→      type: "q:request",
251→      id,
252→      resource,
253→      ...(params ? { params } : {}),
254→    });
255→
256→    if (!sent) {
257→      clearTimeout(timer);
258→      pendingRequests.delete(id);
259→      reject(new Error("WebSocket not connected"));
260→    }
261→  });
262→}
263→
264→/**
265→ * Send a mutation via the q:mutate frame.
266→ * Returns a promise that resolves with the mutation result when the
267→ * server sends q:mutate_result, or rejects on timeout.
268→ */
269→export function sendMutate<T = unknown>(
270→  action: string,
271→  params: Record<string, unknown>
272→): Promise<{ success: boolean; data?: T; error?: string }> {
273→  const id = `mut_${++requestCounter}`;
274→  const MUTATE_TIMEOUT_MS = 30_000;
275→
276→  return new Promise((resolve, reject) => {
277→    const timer = setTimeout(() => {
278→      pendingMutations.delete(id);
279→      reject(new Error(`Mutation ${action} timed out`));
280→    }, MUTATE_TIMEOUT_MS);
281→
282→    pendingMutations.set(id, {
283→      resolve: resolve as (result: { success: boolean; data?: unknown; error?: string }) => void,
284→      reject,
285→      timer,
286→    });
287→
288→    const sent = sendFrame({
289→      type: "q:mutate",
290→      id,
291→      action,
292→      params,
293→    });
294→
295→    if (!sent) {
296→      clearTimeout(timer);
297→      pendingMutations.delete(id);
298→      reject(new Error("WebSocket not connected"));
299→    }
300→  });
301→}
302→
303→/**
304→ * Register a callback for q:event broadcasts.
305→ * Returns an unregister function.
306→ */
307→export function onEvent(callback: EventCallback): () => void {
308→  eventListeners.add(callback);
309→  return () => {
310→    eventListeners.delete(callback);
311→  };
312→}
313→
314→/**
315→ * Send a tool response back to the backend (q:tool_response frame).
316→ * Used by frontend RPC handlers to respond to tool relay requests
317→ * received via q:event with event: "tool:request".
318→ */
319→export function sendToolResponse(requestId: string, result?: unknown, error?: string): boolean {
320→  const frame: Record<string, unknown> = {
321→    type: "q:tool_response",
322→    requestId,
323→  };
324→  if (error !== undefined) {
325→    frame.error = error;
326→  } else {
327→    frame.result = result;
328→  }
329→  return sendFrame(frame);
330→}
331→
332→/**
333→ * Force an immediate reconnection to the backend.
334→ * Used when the backend restarts on a new port — cancels any pending
335→ * backoff timer and closes the stale socket so reconnection picks up
336→ * the new port from getBackendPort().
337→ */
338→export function forceReconnect(): void {
339→  // Cancel any pending reconnect timer so we don't double-connect
340→  if (reconnectTimer) {
341→    clearTimeout(reconnectTimer);
342→    reconnectTimer = null;
343→  }
344→
345→  // Reset backoff counter so the immediate attempt uses minimal delay
346→  reconnectAttempt = 0;
347→
348→  // Close existing socket (if open) — onclose handler will NOT auto-schedule
349→  // because we immediately trigger our own reconnect below.
350→  if (ws) {
351→    // Prevent the onclose handler from scheduling its own reconnect
352→    const staleWs = ws;
353→    ws = null;
354→    connected = false;
355→    connecting = false;
356→    _connectionId = null;
357→    staleWs.onclose = null;
358→    staleWs.close();
359→
360→    notifyConnectionChange(false);
361→  }
362→
363→  // Immediately open a new socket (reads fresh port from getBackendPort())
364→  connecting = true;
365→  openSocket().catch(() => {
366→    connecting = false;
367→    // If this fails, fall back to normal backoff reconnect
368→    scheduleReconnect();
369→  });
370→}
371→
372→/**
373→ * Register a callback for connection state changes.
374→ * Fires with `true` when connected, `false` when disconnected.
375→ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
376→ * Returns an unregister function.
377→ */
378→export function onConnectionChange(callback: (connected: boolean) => void): () => void {
379→  connectionChangeListeners.add(callback);
380→  return () => {
381→    connectionChangeListeners.delete(callback);
382→  };
383→}
384→
385→// ---- Internal ----
386→
387→async function openSocket(serverId?: string): Promise<void> {
388→  const endpoints = await resolveBackendEndpoints(serverId);
389→  const url = endpoints.wsUrl;
390→  const relay = isRelayMode();
391→
392→  ws = new WebSocket(url);
393→
394→  ws.onopen = () => {
395→    if (relay) {
396→      // Relay mode: send authenticate frame with device token
397→      const token = getStoredToken();
398→      if (token) {
399→        sendFrame({ type: "authenticate", token });
400→      } else {
401→        // No token available — close and surface auth failure
402→        console.error("[WS] Relay mode: no device token available for authentication");
403→        ws?.close(4001, "No device token");
404→      }
405→    }
406→    // Localhost/web-dev connections are auto-authenticated by the backend.
407→    // Wait for the "connected" frame in onmessage.
408→  };
409→
410→  ws.onmessage = (evt) => {
411→    let msg: Record<string, unknown>;
412→    try {
413→      msg = JSON.parse(evt.data as string);
414→    } catch {
415→      return;
416→    }
417→
418→    const type = typeof msg.type === "string" ? msg.type : "";
419→
420→    match(type)
421→      .with("connected", () => {
422→        // Localhost/web-dev: backend sends "connected" after auto-auth
423→        _connectionId = msg.connectionId as string;
424→        connected = true;
425→        connecting = false;
426→        reconnectAttempt = 0;
427→
428→        resubscribeAll();
429→        notifyConnectionChange(true);
430→
431→        connectResolve?.();
432→        connectResolve = null;
433→        connectReject = null;
434→      })
435→      .with("authenticated", () => {
436→        // Relay mode: relay confirms device token is valid
437→        connected = true;
438→        connecting = false;
439→        reconnectAttempt = 0;
440→
441→        resubscribeAll();
442→        notifyConnectionChange(true);
443→
444→        connectResolve?.();
445→        connectResolve = null;
446→        connectReject = null;
447→      })
448→      .with("auth_failed", () => {
449→        // Relay mode: device token rejected — sign out (clears storage + React state)
450→        console.error("[WS] Relay auth failed:", msg.message);
451→        signOut();
452→
453→        // Prevent the onclose handler from triggering a reconnect loop
454→        connected = false;
455→        subscriptions.clear();
456→        if (ws) {
457→          ws.onclose = null;
458→          ws.close(4001, "Auth failed");
459→          ws = null;
460→        }
461→
462→        connecting = false;
463→        connectReject?.(new Error(`Relay auth failed: ${msg.message}`));
464→        connectResolve = null;
465→        connectReject = null;
466→
467→        notifyConnectionChange(false);
468→      })
469→      .with("server_reconnecting", () => {
470→        // Relay mode: desktop server disconnected from relay, waiting for reconnect.
471→        // Mark as disconnected so isConnected() returns false — q:request/q:mutate
472→        // will reject immediately instead of sending frames that will time out.
473→        // Keep the WS open — relay will send "server_connected" when server returns.
474→        if (import.meta.env.DEV) {
475→          console.log("[WS] Server reconnecting (relay):", msg);
476→        }
477→        connected = false;
478→
479→        // Reject all pending one-shot requests and mutations
480→        for (const [_id, pending] of pendingRequests) {
481→          clearTimeout(pending.timer);
482→          pending.reject(new Error("Server disconnected — reconnecting"));
483→        }
484→        pendingRequests.clear();
485→
486→        for (const [_id, pending] of pendingMutations) {
487→          clearTimeout(pending.timer);
488→          pending.reject(new Error("Server disconnected — reconnecting"));
489→        }
490→        pendingMutations.clear();
491→
492→        notifyConnectionChange(false);
493→      })
494→      .with("server_connected", () => {
495→        // Relay mode: desktop server reconnected to relay.
496→        // Re-subscribe all active subscriptions.
497→        if (import.meta.env.DEV) {
498→          console.log("[WS] Server reconnected (relay)");
499→        }
500→        connected = true;
501→        resubscribeAll();
502→        notifyConnectionChange(true);
503→      })
504→      .with("ping", () => {
505→        sendFrame({ type: "pong" });
506→      })
507→      .with("q:snapshot", () => {
508→        const sub = subscriptions.get(msg.id as string);
509→        sub?.onSnapshot(msg.data);
510→      })
511→      .with("q:delta", () => {
512→        const sub = subscriptions.get(msg.id as string);
513→        sub?.onDelta?.(
514→          msg.upserted as unknown[] | undefined,
515→          msg.removed as string[] | undefined,
516→          msg.cursor as number | undefined
517→        );
518→      })
519→      .with("q:command_ack", () => {
520→        const pending = pendingCommands.get(msg.id as string);
521→        if (pending) {
522→          pendingCommands.delete(msg.id as string);
523→          pending.resolve({
524→            accepted: msg.accepted as boolean,
525→            commandId: msg.commandId as string | undefined,
526→            error: msg.error as string | undefined,
527→          });
528→        }
529→      })
530→      .with("q:event", () => {
531→        const event = msg.event as string;
532→        const data = msg.data;
533→        for (const cb of eventListeners) {
534→          try {
535→            cb(event, data);
536→          } catch (err) {
537→            console.error("[WS] Event listener error:", err);
538→          }
539→        }
540→      })
541→      .with("q:response", () => {
542→        // One-shot q:request response
543→        const id = msg.id as string;
544→        const pending = pendingRequests.get(id);
545→        if (pending) {
546→          clearTimeout(pending.timer);
547→          pendingRequests.delete(id);
548→          pending.resolve(msg.data);
549→        }
550→      })
551→      .with("q:mutate_result", () => {
552→        // Mutation result
553→        const id = msg.id as string;
554→        const pending = pendingMutations.get(id);
555→        if (pending) {
556→          clearTimeout(pending.timer);
557→          pendingMutations.delete(id);
558→          pending.resolve({
559→            success: msg.success as boolean,
560→            data: msg.data as unknown,
561→            error: msg.error as string | undefined,
562→          });
563→        }
564→      })
565→      .with("q:error", () => {
566→        const id = msg.id as string;
567→        const errorMsg = (msg.message as string) || "Query error";
568→
569→        // Check if this error is for a pending request
570→        const pendingReq = pendingRequests.get(id);
571→        if (pendingReq) {
572→          clearTimeout(pendingReq.timer);
573→          pendingRequests.delete(id);
574→          pendingReq.reject(new Error(errorMsg));
575→          return;
576→        }
577→
578→        // Check if this error is for a pending mutation
579→        const pendingMut = pendingMutations.get(id);
580→        if (pendingMut) {
581→          clearTimeout(pendingMut.timer);
582→          pendingMutations.delete(id);
583→          pendingMut.reject(new Error(errorMsg));
584→          return;
585→        }
586→
587→        // Subscription error (existing behavior)
588→        console.warn("[WS] Query error:", msg.message, "for sub:", id);
589→      })
590→      .otherwise(() => {
591→        // Ignore unknown frame types
592→      });
593→  };
594→
595→  ws.onerror = () => {
596→    // onerror fires before onclose — actual cleanup happens in onclose
597→  };
598→
599→  ws.onclose = () => {
600→    const wasConnected = connected;
601→    connected = false;
602→    _connectionId = null;
603→    ws = null;
604→
605→    // Reject all pending commands immediately — they can't succeed without a connection
606→    for (const [_id, pending] of pendingCommands) {
607→      pending.reject(new Error("WebSocket disconnected"));
608→    }
609→    pendingCommands.clear();
610→
611→    // Reject all pending one-shot requests
612→    for (const [_id, pending] of pendingRequests) {
613→      clearTimeout(pending.timer);
614→      pending.reject(new Error("WebSocket disconnected — request failed"));
615→    }
616→    pendingRequests.clear();
617→
618→    // Reject all pending mutations
619→    for (const [_id, pending] of pendingMutations) {
620→      clearTimeout(pending.timer);
621→      pending.reject(new Error("WebSocket disconnected — mutation failed"));
622→    }
623→    pendingMutations.clear();
624→
625→    if (connecting) {
626→      // Initial connection failed — reject the connect() promise
627→      connecting = false;
628→      connectReject?.(new Error("WebSocket connection failed"));
629→      connectResolve = null;
630→      connectReject = null;
631→    }
632→
633→    if (wasConnected) {
634→      notifyConnectionChange(false);
635→    }
636→
637→    // Only auto-reconnect if we had previously connected or have active subscriptions
638→    if (wasConnected || subscriptions.size > 0) {
639→      scheduleReconnect();
640→    }
641→  };
642→}
643→
644→/** Notify all connection change listeners. */
645→function notifyConnectionChange(state: boolean): void {
646→  for (const cb of connectionChangeListeners) {
647→    try {
648→      cb(state);
649→    } catch (err) {
650→      console.error("[WS] Connection change listener error:", err);
651→    }
652→  }
653→}
654→
655→function sendFrame(frame: Record<string, unknown>): boolean {
656→  if (ws && ws.readyState === WebSocket.OPEN) {
657→    try {
658→      ws.send(JSON.stringify(frame));
659→      return true;
660→    } catch {
661→      // Connection may have closed between readyState check and send
662→      console.warn(`[WS] Failed to send ${frame.type} frame: connection closed during send`);
663→      return false;
664→    }
665→  }
666→  console.warn(`[WS] Dropped ${frame.type} frame: WebSocket not connected`);
667→  return false;
668→}
669→
670→/** Re-subscribe all active subscriptions after reconnect. */
671→function resubscribeAll(): void {
672→  for (const sub of subscriptions.values()) {
673→    sendFrame({
674→      type: "q:subscribe",
675→      id: sub.id,
676→      resource: sub.resource,
677→      ...(sub.params ? { params: sub.params } : {}),
678→    });
679→  }
680→}
681→
682→/** Schedule a reconnection with exponential backoff. */
683→function scheduleReconnect(): void {
684→  if (reconnectTimer) return;
685→
686→  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
687→  reconnectAttempt++;
688→
689→  if (import.meta.env.DEV) {
690→    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
691→  }
692→
693→  reconnectTimer = setTimeout(() => {
694→    reconnectTimer = null;
695→    connecting = true;
696→
697→    // Set up resolve/reject so subscriptions get re-established
698→    connectResolve = null;
699→    connectReject = null;
700→
701→    openSocket().catch(() => {
702→      connecting = false;
703→      // onclose handler will schedule another reconnect
704→    });
705→  }, delay);
706→}
