  1→/**
  2→ * Session Query Hooks
  3→ * TanStack Query hooks for Claude Code session management
  4→ */
  5→
  6→import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
  7→import { produce } from "immer";
  8→import { SessionService } from "./session.service";
  9→import type { PaginatedMessages } from "./session.service";
 10→import { queryKeys } from "@/shared/api/queryKeys";
 11→import { useQuerySubscription } from "@/shared/hooks/useQuerySubscription";
 12→import {
 13→  MESSAGE_PAGE_SIZE,
 14→  INITIAL_MESSAGE_PAGE_SIZE,
 15→  mergeMessageDelta,
 16→} from "../lib/messageCache";
 17→import type { ContentBlock, Message, Session, SessionStatus } from "../types";
 18→import { isToolResultBlock } from "../types";
 19→import type { RepoGroup } from "@shared/types/workspace";
 20→import { useMemo, useCallback } from "react";
 21→import { track } from "@/platform/analytics";
 22→import { parseContentBlocks } from "../lib/contentParser";
 23→import { sendCommand, connect, isConnected } from "@/platform/ws";
 24→import { emitSendAttemptFailed } from "@/features/connection";
 25→import type { RuntimeAgentType } from "../lib/agentRuntime";
 26→
 27→/**
 28→ * Fetch all sessions for a workspace (used by chat tab reconstruction).
 29→ * Stale time is high — tabs only hydrate on mount and after creating new sessions.
 30→ */
 31→export function useWorkspaceSessions(workspaceId: string | null) {
 32→  useQuerySubscription("sessions", {
 33→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 34→    params: { workspaceId: workspaceId || "" },
 35→    enabled: !!workspaceId,
 36→  });
 37→
 38→  return useQuery({
 39→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 40→    queryFn: () => SessionService.fetchByWorkspace(workspaceId!),
 41→    enabled: !!workspaceId,
 42→    staleTime: Infinity,
 43→    refetchOnWindowFocus: false,
 44→  });
 45→}
 46→
 47→/**
 48→ * Fetch session details — fully WS-driven, no polling.
 49→ *
 50→ * Updates come from WS subscription: backend pushes q:snapshot on
 51→ * session:status, session:updated, and session:message notifications.
 52→ * HTTP queryFn is fallback for initial load before WS connects.
 53→ */
 54→export function useSession(sessionId: string | null) {
 55→  useQuerySubscription("session", {
 56→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 57→    params: { sessionId: sessionId || "" },
 58→    enabled: !!sessionId,
 59→  });
 60→
 61→  return useQuery({
 62→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 63→    queryFn: () => SessionService.fetchById(sessionId!),
 64→    enabled: !!sessionId,
 65→    staleTime: Infinity,
 66→    refetchOnWindowFocus: false,
 67→  });
 68→}
 69→
 70→/**
 71→ * Subscribe to per-session working status for multiple sessions at once.
 72→ * Used by the tab bar to show per-tab spinners correctly.
 73→ *
 74→ * The workspace's single `session_status` field breaks with multiple tabs —
 75→ * it gets overwritten by whichever session's event fires last. This hook
 76→ * subscribes to each session's detail cache reactively so tab spinners
 77→ * reflect each session's actual status.
 78→ *
 79→ * No extra HTTP fetches when data is already in cache (populated by
 80→ * the "session" WS subscription via q:snapshot on status changes).
 81→ */
 82→export function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 83→  const queries = useQueries({
 84→    queries: sessionIds.map((id) => ({
 85→      queryKey: queryKeys.sessions.detail(id),
 86→      queryFn: () => SessionService.fetchById(id),
 87→      staleTime: 30_000,
 88→      select: (data: Session): SessionStatus => data.status,
 89→    })),
 90→  });
 91→
 92→  // Derive working IDs from query results. useMemo deps use `queries`
 93→  // directly — React Compiler requires it. The select: data.status
 94→  // ensures queries only change identity when a status actually changes.
 95→  return useMemo(() => {
 96→    const ids = new Set<string>();
 97→    sessionIds.forEach((id, i) => {
 98→      if (queries[i]?.data === "working") ids.add(id);
 99→    });
100→    return ids;
101→  }, [queries, sessionIds]);
102→}
103→
104→/**
105→ * Fetch messages for a session — fully WS-driven.
106→ *
107→ * WS subscription pushes q:delta frames with new messages since last cursor.
108→ * mergeMessageDelta handles the PaginatedMessages shape, deduplication,
109→ * and optimistic placeholder cleanup.
110→ * HTTP queryFn is fallback for initial load before WS connects.
111→ */
112→export function useMessages(sessionId: string | null) {
113→  useQuerySubscription("messages", {
114→    queryKey: queryKeys.sessions.messages(sessionId || ""),
115→    params: { sessionId: sessionId || "" },
116→    enabled: !!sessionId,
117→    mergeDelta: mergeMessageDelta,
118→  });
119→
120→  const query = useQuery({
121→    queryKey: queryKeys.sessions.messages(sessionId || ""),
122→    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
123→    enabled: !!sessionId,
124→    refetchInterval: false,
125→    staleTime: Infinity,
126→    refetchOnWindowFocus: false,
127→  });
128→
129→  return query;
130→}
131→
132→/**
133→ * Combined hook for session + messages + status
134→ * Replaces the complex useMessages hook
135→ */
136→export function useSessionWithMessages(sessionId: string | null) {
137→  const sessionQuery = useSession(sessionId);
138→  const messagesQuery = useMessages(sessionId);
139→
140→  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
141→  const messages = messagesQuery.data?.messages ?? [];
142→  const hasOlder = messagesQuery.data?.has_older ?? false;
143→
144→  // Parse content helper — delegates to pure function in lib/contentParser.ts
145→  // Memoized to prevent Context cascade re-renders
146→  const parseContent = useCallback(
147→    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
148→    []
149→  );
150→
151→  // Build tool result map and parent_tool_use_id map in a single pass.
152→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
153→    const resultMap = new Map();
154→    const parentMap = new Map<string, string>();
155→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
156→
157→    messages.forEach((msg: Message) => {
158→      if (msg.parent_tool_use_id) {
159→        parentMap.set(msg.id, msg.parent_tool_use_id);
160→      }
161→
162→      const blocks = parseContent(msg.content);
163→      if (Array.isArray(blocks)) {
164→        blocks.filter(isToolResultBlock).forEach((block) => {
165→          resultMap.set(block.tool_use_id, block);
166→        });
167→      }
168→    });
169→
170→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
171→  }, [messages, parseContent]);
172→
173→  // Group subagent messages by their parent Task tool_use_id
174→  const subagentMessages = useMemo(() => {
175→    const map = new Map<string, Message[]>();
176→    if (!messages.length) return map;
177→
178→    messages.forEach((msg: Message) => {
179→      const parentId = parentToolUseMap.get(msg.id);
180→      if (parentId) {
181→        if (!map.has(parentId)) map.set(parentId, []);
182→        map.get(parentId)!.push(msg);
183→      }
184→    });
185→
186→    return map;
187→  }, [messages, parentToolUseMap]);
188→
189→  // Get latest user message's sent_at for duration tracking
190→  const latestMessageSentAt = useMemo(() => {
191→    if (!messages.length) return null;
192→
193→    // Find the latest user message
194→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
195→
196→    return latestUserMessage?.sent_at || null;
197→  }, [messages]);
198→
199→  return {
200→    session: sessionQuery.data,
201→    messages,
202→    hasOlder,
203→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
204→    latestMessageSentAt,
205→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
206→    error: sessionQuery.error || messagesQuery.error,
207→    parseContent,
208→    toolResultMap,
209→    parentToolUseMap,
210→    subagentMessages,
211→  };
212→}
213→
214→/**
215→ * Load older messages (scroll-up pagination).
216→ * Prepends older messages to the cache while preserving has_newer from current cache.
217→ */
218→export function useLoadOlderMessages() {
219→  const queryClient = useQueryClient();
220→
221→  return useMutation({
222→    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
223→      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
224→
225→    onSuccess: (olderPage, { sessionId }) => {
226→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
227→        if (!old) return olderPage;
228→        // Deduplicate by id (shouldn't happen, but safety first)
229→        const existingIds = new Set(old.messages.map((m) => m.id));
230→        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
231→        return {
232→          messages: [...newMessages, ...old.messages],
233→          has_older: olderPage.has_older,
234→          has_newer: old.has_newer,
235→        };
236→      });
237→    },
238→  });
239→}
240→
241→/**
242→ * Send message mutation with optimistic update
243→ *
244→ * Shows user message immediately in the chat while request is in flight.
245→ * The optimistic message has a temporary ID that gets replaced on refetch.
246→ */
247→export function useSendMessage() {
248→  const queryClient = useQueryClient();
249→
250→  return useMutation({
251→    mutationFn: async ({
252→      sessionId,
253→      content,
254→      model,
255→      cwd,
256→      agentType,
257→    }: {
258→      sessionId: string;
259→      content: string;
260→      model?: string;
261→      cwd?: string;
262→      agentType?: RuntimeAgentType;
263→    }): Promise<Message | void> => {
264→      // Send message via WS command: backend saves user message to DB,
265→      // forwards to agent-server, and pushes q:delta to subscribers.
266→      if (cwd) {
267→        if (!isConnected()) await connect();
268→        const ack = await sendCommand("sendMessage", {
269→          sessionId,
270→          content,
271→          model,
272→          cwd,
273→          agentType: agentType || "claude",
274→        });
275→        if (!ack.accepted) {
276→          throw new Error(ack.error || "Agent rejected the query");
277→        }
278→        // No return value needed — WS q:delta handles message reconciliation.
279→        return;
280→      }
281→      // Gateway/web fallback: HTTP POST to backend
282→      return SessionService.sendMessage(sessionId, content, model);
283→    },
284→
285→    // Optimistic update: show user message immediately.
286→    // Status indicators (tab spinner, sidebar) are updated by the workspaces
287→    // WS subscription — the sidecar notifies the backend, which pushes fresh
288→    // workspace snapshots within ~50ms.
289→    onMutate: async ({ sessionId, content, model }) => {
290→      await queryClient.cancelQueries({
291→        queryKey: queryKeys.sessions.messages(sessionId),
292→      });
293→
294→      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
295→        queryKeys.sessions.messages(sessionId)
296→      );
297→
298→      // Snapshot workspace-by-repo cache before optimistic update so we can
299→      // restore the exact prior status on error (instead of hardcoding "idle").
300→      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
301→        queryKey: ["workspaces", "by-repo"],
302→      });
303→
304→      // Create optimistic user message
305→      const optimisticId =
306→        typeof crypto !== "undefined" && "randomUUID" in crypto
307→          ? `optimistic-${crypto.randomUUID()}`
308→          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
309→
310→      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
311→      let optimisticContentJson: string;
312→      try {
313→        const parsed = JSON.parse(content);
314→        if (Array.isArray(parsed)) {
315→          optimisticContentJson = JSON.stringify(parsed);
316→        } else {
317→          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
318→        }
319→      } catch {
320→        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
321→      }
322→
323→      const optimisticMessage: Message = {
324→        id: optimisticId,
325→        session_id: sessionId,
326→        seq: Number.MAX_SAFE_INTEGER,
327→        role: "user",
328→        content: optimisticContentJson,
329→        sent_at: new Date().toISOString(),
330→        model: model ?? null,
331→      };
332→
333→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
334→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
335→        return produce(old, (draft) => {
336→          draft.messages.push(optimisticMessage);
337→        });
338→      });
339→
340→      // Optimistically set workspace status to "working" in sidebar cache.
341→      // Handles the startup race where the first IPC event arrives before
342→      // the workspace list has loaded (cache empty → event matching fails).
343→      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
344→        if (!old) return old;
345→        return old.map((group) => ({
346→          ...group,
347→          workspaces: group.workspaces.map((ws) =>
348→            ws.current_session_id === sessionId
349→              ? { ...ws, session_status: "working" as SessionStatus }
350→              : ws
351→          ),
352→        }));
353→      });
354→
355→      return { previousMessages, previousWorkspaceByRepo };
356→    },
357→
358→    onError: (_err, variables, context) => {
359→      // If the error is a WS disconnect, escalate the connection state immediately.
360→      // The WS client produces "WebSocket not connected" (socket already down)
361→      // or "WebSocket disconnected" (connection dropped mid-flight).
362→      if (_err instanceof Error) {
363→        const msg = _err.message.toLowerCase();
364→        if (msg.includes("not connected") || msg.includes("disconnected")) {
365→          emitSendAttemptFailed();
366→        }
367→      }
368→      // Roll back optimistic message
369→      if (context?.previousMessages) {
370→        queryClient.setQueryData(
371→          queryKeys.sessions.messages(variables.sessionId),
372→          context.previousMessages
373→        );
374→      } else {
375→        // No snapshot (first send on empty cache) — invalidate to clear the ghost optimistic message
376→        queryClient.invalidateQueries({
377→          queryKey: queryKeys.sessions.messages(variables.sessionId),
378→        });
379→      }
380→      // Roll back optimistic workspace status from snapshot
381→      if (context?.previousWorkspaceByRepo?.length) {
382→        context.previousWorkspaceByRepo.forEach(([key, data]) => {
383→          queryClient.setQueryData(key, data);
384→        });
385→      } else {
386→        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
387→      }
388→    },
389→
390→    onSettled: async (_, error, variables) => {
391→      if (!error) {
392→        const hasImages = (() => {
393→          try {
394→            const parsed = JSON.parse(variables.content);
395→            return (
396→              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
397→            );
398→          } catch {
399→            return false;
400→          }
401→        })();
402→        const session = queryClient.getQueryData<Session>(
403→          queryKeys.sessions.detail(variables.sessionId)
404→        );
405→        track("session_message_sent", {
406→          session_id: variables.sessionId,
407→          has_images: hasImages,
408→          model: variables.model,
409→          agent_type: session?.agent_type,
410→          message_count: session?.message_count,
411→          context_used_percent: session?.context_used_percent,
412→        });
413→      }
