 1→/**
 2→ * Connection state machine — Zustand store.
 3→ *
 4→ * States:
 5→ *   CONNECTED     → healthy, all systems go
 6→ *   GRACE_PERIOD  → WS just dropped, wait 2s before showing anything
 7→ *   RECONNECTING  → 2-30s, show thin reconnecting bar
 8→ *   DISCONNECTED  → 30s+, show full banner, dim content
 9→ *
10→ * Escalation shortcuts:
11→ *   - If a sendCommand fails while in GRACE_PERIOD or RECONNECTING,
12→ *     immediately jump to DISCONNECTED (user tried to act).
13→ */
14→
15→import { create } from "zustand";
16→import { forceReconnect } from "@/platform/ws";
17→
18→const GRACE_MS = 2_000;
19→const ESCALATE_MS = 30_000;
20→
21→export type ConnectionState = "connected" | "grace_period" | "reconnecting" | "disconnected";
22→
23→interface ConnectionStore {
24→  state: ConnectionState;
25→  disconnectedAt: number | null;
26→  sendAttemptFailed: boolean;
27→  onConnected: () => void;
28→  onDisconnected: () => void;
29→  markSendAttemptFailed: () => void;
30→  retry: () => void;
31→}
32→
33→// Module-level timer refs (not serializable, don't belong in store state)
34→let graceTimer: ReturnType<typeof setTimeout> | null = null;
35→let escalateTimer: ReturnType<typeof setTimeout> | null = null;
36→
37→function clearTimers() {
38→  if (graceTimer) {
39→    clearTimeout(graceTimer);
40→    graceTimer = null;
41→  }
42→  if (escalateTimer) {
43→    clearTimeout(escalateTimer);
44→    escalateTimer = null;
45→  }
46→}
47→
48→export const useConnectionStore = create<ConnectionStore>((set, get) => ({
49→  state: "connected",
50→  disconnectedAt: null,
51→  sendAttemptFailed: false,
52→
53→  onConnected: () => {
54→    clearTimers();
55→    set({ state: "connected", disconnectedAt: null, sendAttemptFailed: false });
56→  },
57→
58→  onDisconnected: () => {
59→    const current = get().state;
60→    // Don't re-enter if already in the active disconnection flow (grace/reconnecting).
61→    // Allow re-entry from "disconnected" so that Retry → forceReconnect → onclose
62→    // can restart the grace period.
63→    if (current === "grace_period" || current === "reconnecting") return;
64→
65→    clearTimers();
66→    set({ state: "grace_period", disconnectedAt: Date.now(), sendAttemptFailed: false });
67→
68→    graceTimer = setTimeout(() => {
69→      if (get().state !== "grace_period") return;
70→
71→      set({ state: "reconnecting" });
72→
73→      // Escalate to DISCONNECTED after ESCALATE_MS total from initial disconnect
74→      // (not from entering RECONNECTING). Accounts for time already in GRACE_PERIOD.
75→      const disconnectedAt = get().disconnectedAt;
76→      if (!disconnectedAt) return;
77→
78→      const remaining = Math.max(0, ESCALATE_MS - (Date.now() - disconnectedAt));
79→      escalateTimer = setTimeout(() => {
80→        if (get().state === "reconnecting") {
81→          set({ state: "disconnected" });
82→        }
83→      }, remaining);
84→    }, GRACE_MS);
85→  },
86→
87→  markSendAttemptFailed: () => {
88→    const current = get().state;
89→    if (current === "grace_period" || current === "reconnecting") {
90→      clearTimers();
91→      set({ state: "disconnected", sendAttemptFailed: true });
92→    }
93→  },
94→
95→  retry: () => {
96→    forceReconnect();
97→  },
98→}));
