132→/**
133→ * Combined hook for session + messages + status
134→ * Replaces the complex useMessages hook
135→ */
136→export function useSessionWithMessages(sessionId: string | null) {
137→  const sessionQuery = useSession(sessionId);
138→  const messagesQuery = useMessages(sessionId);
139→
140→  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
141→  const messages = messagesQuery.data?.messages ?? [];
142→  const hasOlder = messagesQuery.data?.has_older ?? false;
143→
144→  // Parse content helper — delegates to pure function in lib/contentParser.ts
145→  // Memoized to prevent Context cascade re-renders
146→  const parseContent = useCallback(
147→    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
148→    []
149→  );
150→
151→  // Build tool result map and parent_tool_use_id map in a single pass.
152→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
153→    const resultMap = new Map();
154→    const parentMap = new Map<string, string>();
155→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
156→
157→    messages.forEach((msg: Message) => {
158→      if (msg.parent_tool_use_id) {
159→        parentMap.set(msg.id, msg.parent_tool_use_id);
160→      }
161→
162→      const blocks = parseContent(msg.content);
163→      if (Array.isArray(blocks)) {
164→        blocks.filter(isToolResultBlock).forEach((block) => {
165→          resultMap.set(block.tool_use_id, block);
166→        });
167→      }
168→    });
169→
170→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
171→  }, [messages, parseContent]);
172→
173→  // Group subagent messages by their parent Task tool_use_id
174→  const subagentMessages = useMemo(() => {
175→    const map = new Map<string, Message[]>();
176→    if (!messages.length) return map;
177→
178→    messages.forEach((msg: Message) => {
179→      const parentId = parentToolUseMap.get(msg.id);
180→      if (parentId) {
181→        if (!map.has(parentId)) map.set(parentId, []);
182→        map.get(parentId)!.push(msg);
183→      }
184→    });
185→
186→    return map;
187→  }, [messages, parentToolUseMap]);
188→
189→  // Get latest user message's sent_at for duration tracking
190→  const latestMessageSentAt = useMemo(() => {
191→    if (!messages.length) return null;
192→
193→    // Find the latest user message
194→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
195→
196→    return latestUserMessage?.sent_at || null;
197→  }, [messages]);
198→
199→  return {
200→    session: sessionQuery.data,
201→    messages,
202→    hasOlder,
203→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
204→    latestMessageSentAt,
205→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
206→    error: sessionQuery.error || messagesQuery.error,
207→    parseContent,
208→    toolResultMap,
209→    parentToolUseMap,
210→    subagentMessages,
211→  };
212→}
