214→/**
215→ * Load older messages (scroll-up pagination).
216→ * Prepends older messages to the cache while preserving has_newer from current cache.
217→ */
218→export function useLoadOlderMessages() {
219→  const queryClient = useQueryClient();
220→
221→  return useMutation({
222→    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
223→      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
224→
225→    onSuccess: (olderPage, { sessionId }) => {
226→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
227→        if (!old) return olderPage;
228→        // Deduplicate by id (shouldn't happen, but safety first)
229→        const existingIds = new Set(old.messages.map((m) => m.id));
230→        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
231→        return {
232→          messages: [...newMessages, ...old.messages],
233→          has_older: olderPage.has_older,
234→          has_newer: old.has_newer,
235→        };
236→      });
237→    },
238→  });
239→}
