241→/**
242→ * Send message mutation with optimistic update
243→ *
244→ * Shows user message immediately in the chat while request is in flight.
245→ * The optimistic message has a temporary ID that gets replaced on refetch.
246→ */
247→export function useSendMessage() {
248→  const queryClient = useQueryClient();
249→
250→  return useMutation({
251→    mutationFn: async ({
252→      sessionId,
253→      content,
254→      model,
255→      cwd,
256→      agentType,
257→    }: {
258→      sessionId: string;
259→      content: string;
260→      model?: string;
261→      cwd?: string;
262→      agentType?: RuntimeAgentType;
263→    }): Promise<Message | void> => {
264→      // Send message via WS command: backend saves user message to DB,
265→      // forwards to agent-server, and pushes q:delta to subscribers.
266→      if (cwd) {
267→        if (!isConnected()) await connect();
268→        const ack = await sendCommand("sendMessage", {
269→          sessionId,
270→          content,
271→          model,
272→          cwd,
273→          agentType: agentType || "claude",
274→        });
275→        if (!ack.accepted) {
276→          throw new Error(ack.error || "Agent rejected the query");
277→        }
278→        // No return value needed — WS q:delta handles message reconciliation.
279→        return;
280→      }
281→      // Gateway/web fallback: HTTP POST to backend
282→      return SessionService.sendMessage(sessionId, content, model);
283→    },
284→
285→    // Optimistic update: show user message immediately.
286→    // Status indicators (tab spinner, sidebar) are updated by the workspaces
287→    // WS subscription — the sidecar notifies the backend, which pushes fresh
288→    // workspace snapshots within ~50ms.
289→    onMutate: async ({ sessionId, content, model }) => {
290→      await queryClient.cancelQueries({
291→        queryKey: queryKeys.sessions.messages(sessionId),
292→      });
293→
294→      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
295→        queryKeys.sessions.messages(sessionId)
296→      );
297→
298→      // Snapshot workspace-by-repo cache before optimistic update so we can
299→      // restore the exact prior status on error (instead of hardcoding "idle").
300→      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
301→        queryKey: ["workspaces", "by-repo"],
302→      });
303→
304→      // Create optimistic user message
305→      const optimisticId =
306→        typeof crypto !== "undefined" && "randomUUID" in crypto
307→          ? `optimistic-${crypto.randomUUID()}`
308→          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
309→
310→      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
311→      let optimisticContentJson: string;
312→      try {
313→        const parsed = JSON.parse(content);
314→        if (Array.isArray(parsed)) {
315→          optimisticContentJson = JSON.stringify(parsed);
316→        } else {
317→          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
318→        }
319→      } catch {
320→        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
321→      }
322→
323→      const optimisticMessage: Message = {
324→        id: optimisticId,
325→        session_id: sessionId,
326→        seq: Number.MAX_SAFE_INTEGER,
327→        role: "user",
328→        content: optimisticContentJson,
329→        sent_at: new Date().toISOString(),
330→        model: model ?? null,
331→      };
332→
333→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
334→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
335→        return produce(old, (draft) => {
336→          draft.messages.push(optimisticMessage);
337→        });
338→      });
339→
340→      // Optimistically set workspace status to "working" in sidebar cache.
341→      // Handles the startup race where the first IPC event arrives before
342→      // the workspace list has loaded (cache empty → event matching fails).
343→      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
344→        if (!old) return old;
345→        return old.map((group) => ({
346→          ...group,
347→          workspaces: group.workspaces.map((ws) =>
348→            ws.current_session_id === sessionId
349→              ? { ...ws, session_status: "working" as SessionStatus }
350→              : ws
351→          ),
352→        }));
353→      });
354→
355→      return { previousMessages, previousWorkspaceByRepo };
356→    },
357→
358→    onError: (_err, variables, context) => {
359→      // If the error is a WS disconnect, escalate the connection state immediately.
360→      // The WS client produces "WebSocket not connected" (socket already down)
361→      // or "WebSocket disconnected" (connection dropped mid-flight).
362→      if (_err instanceof Error) {
363→        const msg = _err.message.toLowerCase();
364→        if (msg.includes("not connected") || msg.includes("disconnected")) {
365→          emitSendAttemptFailed();
366→        }
367→      }
368→      // Roll back optimistic message
369→      if (context?.previousMessages) {
370→        queryClient.setQueryData(
371→          queryKeys.sessions.messages(variables.sessionId),
372→          context.previousMessages
373→        );
374→      } else {
375→        // No snapshot (first send on empty cache) — invalidate to clear the ghost optimistic message
376→        queryClient.invalidateQueries({
377→          queryKey: queryKeys.sessions.messages(variables.sessionId),
378→        });
379→      }
380→      // Roll back optimistic workspace status from snapshot
381→      if (context?.previousWorkspaceByRepo?.length) {
382→        context.previousWorkspaceByRepo.forEach(([key, data]) => {
383→          queryClient.setQueryData(key, data);
384→        });
385→      } else {
386→        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
387→      }
388→    },
389→
390→    onSettled: async (_, error, variables) => {
391→      if (!error) {
392→        const hasImages = (() => {
393→          try {
394→            const parsed = JSON.parse(variables.content);
395→            return (
396→              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
397→            );
398→          } catch {
399→            return false;
400→          }
401→        })();
402→        const session = queryClient.getQueryData<Session>(
403→          queryKeys.sessions.detail(variables.sessionId)
404→        );
405→        track("session_message_sent", {
406→          session_id: variables.sessionId,
407→          has_images: hasImages,
408→          model: variables.model,
409→          agent_type: session?.agent_type,
410→          message_count: session?.message_count,
411→          context_used_percent: session?.context_used_percent,
412→        });
413→      }
414→      // No incrementalFetchAndMerge needed — WS q:delta handles reconciliation.
415→      // The optimistic message stays visible until the delta arrives with the real message.
416→    },
417→  });
418→}
